window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q06"]=window.__LIBQ["tien-nghich"]["q06"]||{};window.__LIBQ["tien-nghich"]["q06"]["cotTruyen"]=[{"chuong":458,"tieuDe":"Kiếm Ý","tomTat":"Trương Hướng Phàm ấn lệnh bài vào chỗ ba đạo bạch ngân giao nhau trong trận pháp Phẩm Linh Các, kích hoạt cánh cửa truyền tống tại tầng thứ bảy rồi cung kính mời Thất sư tổ Vương Lâm tiến vào. Vương Lâm được đưa tới một tiên cảnh đầy hương hoa, mây bảy sắc và tiên hạc, nơi một nhân ảnh khổng lồ canh giữ xác nhận hắn là Đệ thất tử Tử hệ đã 103 năm chưa lĩnh tiên ngọc. Hắn chọn lấy toàn bộ và kinh ngạc khi 123.600 khối tiên ngọc bay ra chất cao như núi, đỏ mắt thu hết vào túi trữ vật, ngầm nghi vấn vì sao Thiên Vận tông lại nhiều tiên ngọc đến vậy. Trở ra, Vương Lâm hóa cầu vồng về Tử Lâm Các, dự định bế quan ba tháng để đột phá Anh Biến trung kỳ và tranh đoạt danh hiệu thiên vận thất tử. Trong một tòa lầu trúc, ba chấp pháp trưởng lão bàn luận về hắn, nhắc lệnh của Thủy tổ là chỉ cần không phạm môn quy thì khỏi quản, và bàn về sự khốc liệt của cạnh tranh nội bộ. Vừa về tới Tử Lâm Các, Vương Lâm liền bị năm người hợp vây gồm tứ sư tỷ Tử hệ, Triệu Tinh Sát, đệ tử thứ hai Lam tông, Tư Mã Như Phong v�� một người y phục xanh nửa bước vấn đỉnh. Tứ sư tỷ bất đắc dĩ thừa nhận được người nhờ vả, bắt quyết thi triển Tử thuật - Na di, một tia sáng bạc bao trùm mười dặm mở màn cuộc chiến."},{"chuong":459,"tieuDe":"Khốn Địa Tu Luyện","tomTat":"Tứ sư tỷ cùng Triệu Tinh Sát, nhị sư huynh và hai người Thanh-Lam hai hệ liên thủ khóa không gian, phát bốn đạo sát khí chấn nhiếp rồi dùng thần thông na di đưa Vương Lâm tới một thạch lâm khốn địa hoang vu cách Thiên Vận Tông hơn mười ngàn dặm. Tứ sư tỷ hẹn ba năm sau tới thả ra, hứa sẽ truyền thần thông na di, rồi tuyên bố với đại sư huynh rằng nhân tình năm xưa nay đã hồi báo, từ nay không còn liên quan, trước khi hóa ngân quang bay về tông. Vương Lâm thử phá vây bằng tiên kiếm chém kiếm quang nhưng bị triệt tiêu, bay thẳng lên trên thì gặp lực cản tương đương Anh Biến hậu kỳ đè bật trở lại. Hắn cho Hứa Lập Quốc trong tiên kiếm cùng loan đao lao thử nhưng vẫn không phá nổi trận pháp do đại sư huynh bố trí. Nhận ra kẻ địch muốn vây tới khi tranh đoạt danh hiệu Thiên Vận Thất Tử kết thúc, hắn quyết tự phá nơi này thay vì chờ ba năm. Vương Lâm tìm được biên giới thạch lâm, ngồi khoanh chân hấp thu lượng lớn tiên ngọc luyện công, sau lưng hiện quầng sáng vàng báo hiệu tiên lực đạt bão hòa, hướng tới đột phá Anh Biến trung kỳ."},{"chuong":460,"tieuDe":"Thọ Yến","tomTat":"Tiên lực điên cuồng nhập thể Vương Lâm, hắn dồn toàn lực hấp thu suốt ba tháng tại thạch lâm cách Thiên Vận Tông hơn mười ngàn dặm. Cùng lúc, cả Thiên Vận Tinh náo động chuẩn bị đại thọ ngàn năm của Thiên Vận Tử — tử vụ đại trận tạm ngừng vận động, đệ tử thất tông nghênh đón tu sĩ bản địa, năm tiểu tinh cầu, lão quái các tiểu tu chân tinh, cả sứ giả huyền trấn liên minh đổ về. Triệu Tinh Sát — đại sư huynh Tử hệ — canh giữ tử vụ đại trận, độc thoại điểm danh sáu vị tử khác (lão nhị bỏ cuộc, lão tam coi thường, lão tứ nữ có cách giữ, lão ngũ bị phạt thiên ngục, lão lục sinh tử chưa rõ) và cảnh cáo lão thất chớ tranh đoạt danh hiệu Thiên Vận thất tử với mình. Kim Ma tử — tôn giả độc chiếm một tiểu tinh, thân tròn như cầu thịt da trong như thủy tinh, đồn đạt Hư Thật nhị ý — đáp chiến xa vàng do bốn yêu thú nâng đỡ tới chúc thọ, được Triệu Tinh Sát cung kính dẫn về, dù thân phận chỉ đủ ngồi tiệc Xích tông. Thọ yến chia tám chỗ cho thất tông và Thiên Vận Tử, số người được vào Thiên Vận Tông không quá trăm. Cuối chương, một nam tử tóc dài tại thạch lâm mở mắt phát quang như trăng rằm, nhấn tay phá nát thạch lâm mười dặm, há miệng hút thu khí tức như phễu rồi thét dài chấn động thiên địa — khả năng cao chính là Vương Lâm hoàn tất bước đột phá."},{"chuong":461,"tieuDe":"Tử Khí Đông Lai","tomTat":"Sau ba tháng bị tấm màn sáng hình vòm vây khốn trong thạch lâm rộng mười dặm, Vương Lâm bay lên sát đỉnh màn dùng Tịch Diệt Chỉ điểm tạo vết nứt nhưng trận tự khôi phục. Hắn chuyển sang Hóa Ma Chỉ, nghịch hóa toàn bộ tiên lực thành ma hỏa tím; nhờ đã đột phá Anh Biến trung kỳ bằng tiên ngọc, hắn thiêu rụi cả tấm màn chỉ trong ba nhịp thở. Không thuộc địa hình, Vương Lâm phất hồn phiên thả nguyên thần Tào Nhất Đấu, được chỉ hướng tây ba mươi vạn dặm tới sơn môn Thiên Vận Tông. Trên đường hắn hồi tưởng bị Tử hệ nhất mạch và Triệu Tinh Sát na di vây khốn, lập thề ai phạm ta giết không tha. Sau giờ ngọ ngày thứ hai, hắn tới giữa thọ yến ngàn năm của sư tôn Thiên Vận Tử, nơi Tử tông bày tiệc náo nhiệt và sáu đại trưởng lão tông phái nhỏ cùng dự. Đúng lúc đại sư huynh Triệu Tinh Sát đứng dậy chúc rượu, một đạo cầu vồng màu tím từ chân trời đằng đông lao thẳng tới, báo trước cuộc đối đầu."},{"chuong":462,"tieuDe":"Xông Vào Yến Tiệc","tomTat":"Một đám mây tím phá không bay tới Tử Tông Sơn trên Thiên Vận Tinh, kinh động buổi thọ yến của sư tôn Tử hệ; Triệu Tinh Sát bóp nát chén rượu khi nhận ra Vương Lâm chẳng những thoát vây mà còn đột phá Anh Biến Trung Kỳ. Nhị sư huynh Hứa Lập Quốc hóa tử quang nghênh chiến, phóng Thượng chi lực hóa đám cát như bầy ong nhưng bị Vương Lâm dùng Cấm Phiên tạo cơn lốc cấm chế đen xé tan. Vương Lâm cảnh cáo các tu sĩ tông phái khác không được can dự, rồi khơi ma hỏa quyết đòi mạng kẻ thù. Khi Triệu Tinh Sát bước ra dùng Đại tự tại thiên địa quyết bọc ma hỏa, Vương Lâm hô “Bạo”, ma hỏa tự nổ thiêu vỡ quầng sáng trắng, quét nghìn trượng tạo hố lớn khiến mọi tu sĩ tản chạy. Vương Lâm vung tiên kiếm cùng loan đao truy sát; Hứa Lập Quốc dùng cấm thuật Tiên Ma thể hóa sương mù đen hòng trốn nhưng bị chém tan, lộ tên thật. Cuối cùng Vương Lâm dùng Côn Cực Tiên kéo dài đánh trúng nguyên thần đang thuấn di cách nghìn trượng, khiến nguyên thần trọng thương sắp tan, phát tiết lượng lớn tiên lực tinh hoa, trong khi Triệu Tinh Sát đứng nhìn cười lạnh không cứu."},{"chuong":463,"tieuDe":"Cổ Yêu","tomTat":"Vương Lâm dịch chuyển bắt lấy nguyên thần đang hoảng sợ ném vào Tôn Hồn Phiên rồi chỉ thẳng Triệu Tinh Sát, tuyên bố ai cản trở sẽ thành kẻ thù; các chấp pháp trưởng lão Tử Tông do dự không dám tiến. Triệu Tinh Sát quay sang cầu viện lão tứ, nhưng nữ tử bình thản đáp ân tình ba tháng trước đã đền đáp và đã đồng ý không tranh danh hiệu Thiên Vận Thất Tử, khiến hắn mất chỗ dựa. Bị dồn ép, Triệu Tinh Sát dùng trước thuật triệu Cổ Yêu vốn định để dành: ký hiệu cổ quái lóe giữa lông mày gọi ra hư ảnh yêu vật trăm trượng, càng dùng thân thể càng suy yếu. Khương Thiên Tôn, trưởng lão Vấn Đỉnh Hậu Kỳ của Thủy Vân Môn, nhận ra đó là cổ yêu trong truyền thuyết thượng cổ và gọi tên Yêu lực — khí tức vượt xa linh lực, ngang tiên lực và ma hỏa. Vương Lâm dùng Tôn Hồn Phiên thu hồi chủ hồn bị lốc xoáy đỏ hút, rồi triệu Hồn Thú từ Xạ Thần Xa đâm xuyên thân cổ yêu. Khi cổ yêu định nuốt Hồn Thú, từ tổng tông vang tiếng hét của Xích Liệt sư thúc buộc nó rút lui, Triệu Tinh Sát phun máu cười u ám. Vương Lâm điềm tĩnh thu Khu Thú Quyển, ung dung về ngồi vào chỗ của mình; Triệu Tinh Sát cung kính tham kiến Xích Liệt, xác nhận từng gặp mặt mấy ngàn năm trước."},{"chuong":464,"tieuDe":"Cửu Chuyển Luyện Tiên Quyết","tomTat":"Xích Liệt khẳng định yêu linh trong Triệu Sát Tinh vừa hình thành đã gượng sử dụng nên áp giải hắn về cho sư phụ trừng phạt, đồng thời tiết lộ sư phụ kỳ vọng cao ở Vương Lâm và đại sư huynh Tử hệ sẽ không tranh danh hiệu Thiên Vận Thất Tử, rồi hóa mây đỏ bay đi. Vương Lâm trở thành tâm điểm yến hội ngày cuối, được các tu sĩ tông phái kéo đến chúc rượu; đêm khuya tứ sư tỷ trao một ngọc giản chứa cấm pháp Đại Na Di cùng một cấm pháp do sư tôn phỏng theo hạ phẩm tiên thuật, coi như xin lỗi việc tháng trước. Trên đường về Tử Vi Các, Bạch Vi lộ vẻ ác độc, trách sư tôn đã cấy yêu linh vào đại sư huynh khiến kế hoạch báo thù lung lay. Về mật thất Tử Lâm Các, Vương Lâm thử thành công Đại Na Di — bước bảy bước trong hào quang bạc rồi xuất hiện trên đỉnh núi cách mười vạn dặm, xác nhận đã đứng đúng trên Thiên Vận Tinh. Sau đó hắn tới thung lũng hẻo lánh, đặt tên cấm pháp thứ hai là Cửu Chuyển Luyện Tiên Quyết, lần lượt tu thành nhất chuyển, nhị chuyển, tam chuyển và ngưng luồng kim tiên lực sắc bén ở tay trái — đánh dấu lần đầu tu thành tiên thuật chân chính. Trời sáng, lễ giảng đạo vạn năm một lần của Thiên Vận Tử bắt đầu, bảy hệ tông Xích, Chanh, Hoàng, Lục, Thanh, Lam, Tử lần lượt xuất hiện kính bái, Tử Tông chỉ ba người nên bị sáu tông khinh bỉ châm biếm. Vương Lâm quét mắt nhận ra ba cao thủ: Tư Mã Như Phong Anh Biến đại viên mãn của Lam Tông, một nam tử họ Vương mặt lạnh của Thanh Tông đã bước nửa bước vào Vấn Đỉnh, và người trung niên vị trí thứ tư Cam Tông — chính là người năm xưa ở tiên giới đánh nhau với Sất Hổ bằng Sát Khí Huyết Tinh, nay đã Anh Biến Hậu Kỳ."},{"chuong":465,"tieuDe":"Tôn Trưởng Lão!","tomTat":"Tại đại thọ vạn năm của Thiên Vận Tử, Vương Lâm với thân phận đệ tử Tử Hệ đánh giá thực lực thất hệ, nhận thấy nhiều đệ tử ẩn giấu bản lãnh và trừ Tử Hệ thì các Hệ khác đều có thể hoành hành ở Chu Tước Tinh. Tứ sư tỷ truyền âm than thở rằng Tử Tông đang sa sút vì tranh đoạt nội bộ, danh hiệu Thiên Vận Thất Tử đổi quá thường xuyên, không còn uy phong như thời Tôn Vân sư đệ. Thiên Vận Tử xuất hiện trên quầng sáng bảy màu, được toàn tông và vô số tu sĩ tham bái, rồi bất ngờ mời lão bằng hữu từ tu chân liên minh. Tôn trưởng lão giáng lâm bằng đạo kim quang vạn trượng ngưng tụ thành trận pháp khổng lồ, dáng vẻ khoảng bốn mươi tuổi mặc trường bào tím, uy áp khiến các cao thủ phải cúi đầu. Ông tặng phi kiếm trung phẩm tiên khí ngưng luyện vạn năm, Thiên Vận Tử nhận rồi tặng lại Côn Bằng Tử của Hoàng Hệ. Khi Thiên Vận Tử bắt đầu giảng Thiên Vận Chi Đạo, con tiểu điêu ba mắt của Tôn trưởng lão bay tới đậu lên vai Vương Lâm dò xét, khiến hắn thấy quen quen và chăm chú quan sát."},{"chuong":466,"tieuDe":"Hắn!","tomTat":"Vương Lâm nhìn con tử điêu ba mắt đậu trên vai và qua truyền thừa ký ức cổ thần Đồ Ti nhận ra đó là Tinh Ngân điêu còn nhỏ — loài sinh vật hiếm trưởng thành có thể biến ảo thành vạn vật, hóa hình người, là tài liệu tốt nhất chế con rối thần thông. Con chim không màng thượng phẩm tinh thạch mà chỉ chăm chú nhìn hắn vì bị khí tức cổ thần cực yếu trên người hắn thu hút, rồi đoạt nuốt liền hai khối tiên ngọc với tốc độ chỉ thấy tử quang lóe lên trước khi đậu sang vai Tôn trưởng lão. Trên tường vân, Thiên Vận Tử bắt đầu giảng đạo, liệt kê bảy cảnh từ Ngưng Khí tới Vấn Đỉnh thuộc bước một chữ ‘tu’, bước hai là hư thực nhị ý và toái niết tam cảnh nơi hầu hết tu sĩ phải dừng chân do một lực lượng trong cõi u minh nhiễu loạn. Một hắc y nhân mặt sẹo tỏa hung khí trầm giọng hỏi về bước thứ ba, được Thiên Vận Tử giải thích đó là chữ ‘đạo’ cầu thiên vận, tu thành đạt độ cao không ngờ nhưng cách tu thành thì không ai biết. Được sư tôn gọi đích danh, Vương Lâm vấn đạo phân biệt tu tiên, tu chân, tu đạo: tiên giới đã mất nên ‘tiên’ và ‘chân’ thành quá khứ, nay tu sĩ chỉ truy tìm ‘đạo’ mà không phải thiên đạo, khiến tu sĩ bốn phía tranh cãi cuồn cuộn. Khi Vương Lâm tỏ ý hoài nghi có thực sự tồn tại bước thứ ba, Thiên Vận Tử bồi hồi tiết lộ ba ngàn năm trước nhờ gặp được ‘hắn’ mới tin, lời này khiến Tôn trưởng lão lộ vẻ sợ hãi và cả hội trường trầm mặc dị thường."},{"chuong":467,"tieuDe":"Gặp Lại Lăng Thiên Hầu","tomTat":"Sau khi nhắc tới một nhân vật bí ẩn, Thiên Vận Tử bị tu sĩ truy hỏi và tiết lộ “hắn” là kẻ duy nhất lão biết đã đạt tới bước thứ ba, từng khiến Tu Chân Liên Minh nếm khổ một lần rồi biệt tích. Buổi giảng đạo ba ngày nhân đại thọ vạn năm kết thúc, Vương Lâm im lặng lắng nghe và dần có lĩnh ngộ. Theo lệ, Thiên Vận Tử tuyên bố sẽ thi triển một trung phẩm Tiên thuật — điều cực hiếm khiến đông đảo tu sĩ tề tựu, và là lần đầu Vương Lâm được thấy Tiên thuật thật. Đúng lúc đó, Kiếm Tôn Lăng Thiên Hầu, Tông chủ Đại La Kiếm Tông, cưỡi biển phi kiếm cùng hơn vạn đệ tử áo đen xuất hiện, sau lưng có bốn bóng kiếm hư ảo, dưới chân là xà hình bảo kiếm mà Vương Lâm nhận ra chính là Vũ chi đệ nhị kiếm. Lăng Thiên Hầu lạnh lùng đồng ý làm đối tượng để Thiên Vận Tử thi triển Dẫn Tiên thuật. Thiên Vận Tử phóng xích mang lên trời, hiện ra mảnh đỏ mây cuộn như rồng và sấm sét như rắn bạc, kèm thiên uy ép đa số tu sĩ tái mặt phải ngồi xuống; Vương Lâm vận tam chuyển kim tiên lực lưu chuyển toàn thân để chống đỡ và dần đứng vững lại."},{"chuong":468,"tieuDe":"Dẫn Tiên Thuật!","tomTat":"Khảo nghiệm áp lực kết thúc, Bạch Vi ngồi sụp xuống đất, cả Tử hệ chỉ còn Vương Lâm và Tứ sư tỷ trụ vững — Vương Lâm vận kim tiên lực ba vòng khôi phục, được Tứ sư tỷ liếc nhìn thâm ý. Thiên Vận Tử đổi hướng nhắm vào đệ tử Đại La Kiếm Tông, hô “Dẫn độ” thi triển Dẫn Tiên thuật cuốn hơn vạn đệ tử mê man bay lên hư không. Lăng Thiên Hầu thúc xà hình phi kiếm bị bắt giữ, triệu Kỳ Lân thú từ mi tâm lao tới, nhưng Tôn Hồn Phiên trong nguyên thần Vương Lâm phát tiếng gầm cộng hưởng khiến Kỳ Lân thú dừng lại, buộc hắn vội che giấu tàn hồn. Hư ảnh sứ giả Tiên giới mặc trường bào vàng hiện thân, ấn chưởng kim sắc phong kín toàn bộ đệ tử đưa vào hư không, khiến tu sĩ dự thọ kinh hãi và nghi ngờ về nguồn gốc Trung phẩm Tiên thuật. Lăng Thiên Hầu trách móc nhưng đành nhẫn nhịn chờ ba ngày đệ tử trở về, còn Thiên Vận Tử muốn mượn người hỏi xem đã đến đâu. Cuối cùng lão tuyên bố Hoàng hệ và Tử hệ hôm nay sẽ xuất hiện người mang phong hiệu Thiên Vận Thất tử, hé lộ chuyện lão Tam Hoàng hệ từng đạt phong hiệu rồi mất tích ở tinh không ba mươi năm trước."},{"chuong":469,"tieuDe":"Triệu Hân Mộng","tomTat":"Trong cuộc phân phong hiệu Thiên Vận Thất tử, sáu đệ tử Hoàng hệ lần lượt bỏ cuộc; cuối cùng lão đại Vận Đường — từng giữ phong hiệu hơn 800 năm rồi bị lão Tam đoạt — cũng nhường ngôi, đề cử Nhị sư đệ Côn Bằng Tử. Thiên Vận Tử trao Côn Bằng Tử khối tinh thể vàng dấu hiệu phong hiệu, hứa truyền Hạ phẩm Tiên thuật và bảo mệnh pháp bảo, để hắn vào bế quan. Vương Lâm phát hiện Vận Đường lộ biểu hiện quỷ dị và ánh mắt sợ hãi khi tinh thể vàng xuất hiện. Tứ sư tỷ Triệu Hân Mộng khiêu chiến Vương Lâm để hắn không đạt phong hiệu quá dễ dàng; Vương Lâm ban đầu định bỏ cuộc nhưng bị Thiên Vận Tử đích thân khuyên — người thứ hai sau Tôn Vân — nên đổi ý khai chiến. Triệu Hân Mộng dùng Tử Ma thủ mô phỏng từ Hoá Ma chỉ qua Yêu ảnh đạo, Vương Lâm đáp trả bằng Hoá Ma chỉ khiến ma khí ngập trời. Thiên Vận Tử độc thoại về ‘hắn’ gặp ba vạn năm trước và bước thứ ba của Thiên Vận đạo, xét Vương Lâm có phải người phù hợp số phận, ánh mắt cuối cùng lộ một tia chán nản."},{"chuong":470,"tieuDe":"Tử Hệ Lão Lục","tomTat":"Vương Lâm thi Hoá Ma chỉ đối đầu Tử Ma thủ của Triệu Hân Mộng; nàng dùng hạt châu hút ma lực hòng cướp đoạt, nhưng Vương Lâm vạch trần ma lực chỉ là tia hư ảo do tiên lực chuyển hoá và khiến nó tự sụp, viện lời hứa với Tư Đồ Nam mà từ chối nhường. Hai bên đấu Cửu chuyển luyện tiên quyết: Vương Lâm dù mới nhận công pháp vài ngày đã tu tới ngũ chuyển, lại rút chiến phủ Cự Ma Tộc và Xạ Thần xa, khiến Triệu Hân Mộng thừa nhận xem thường hắn rồi bỏ cuộc. Tiếp đó Tử hệ Lão Lục Trần Đào — đệ tử lâu năm từng đạt phong hiệu Thiên Vận Thất tử trước Tôn Vân — trở về dâng Thất thải lưu ly quang (kỳ bảo xếp thứ 93 Tu Chân Liên Minh) cho Thiên Vận Tử và đòi tranh lại phong hiệu. Thiên Vận Tử phán chỉ Trần Đào và Vương Lâm đủ tư cách nhưng chỉ một người đạt. Trần Đào khinh thường Vương Lâm rồi giao chiến: đẩy ngũ chuyển kim tiên lực lên cửu chuyển phản công, còn Vương Lâm dùng Đại Na Di làm cơn lốc biến mất rồi triệu Hồn thú chấn động cả trường. Trần Đào nổ tan đòn nuốt của Hồn thú, xé áo rút trường thằng đen nghênh chiến khi trận đấu còn dang dở."},{"chuong":471,"tieuDe":"Chiến Vấn Đỉnh!","tomTat":"Trong trận đấu tại lễ chúc thọ, Trần Đào khoe Long cân rút từ xác yêu long ở Yêu Tinh, vung từ góc độ khó tin buộc cổ Hồn thú của Vương Lâm rồi đứng trên đầu nó siết chặt khống chế. Vương Lâm bình thản kết ấn, lần đầu mở đạo phong ấn thứ nhất của Xạ Thần xa — pháp bảo bắn hạ được thần tiên mà hắn chưa từng dám mở vì sợ bị cắn trả, nay nhờ đạt Anh Biến trung kỳ mới đủ vài phần nắm chắc. Hồn thú đang bị khốn bỗng phát điên, bành trướng từ mười trượng lên hơn trăm trượng, hóa hắc mang phản công Trần Đào và đoạt được một số thiên uy thần thông. Trần Đào dựng tử sắc quang cầu phòng ngự nhưng vẫn bị tổn thương, sắc mặt khó coi vẫn nồng nặc chiến ý, mỉa mai Vương Lâm “có tư cách làm sư đệ”, bị phản bác rồi hóa tàn ảnh lao tới tấn công. Biết mình không phải đối thủ Vấn Đỉnh kỳ nhưng không từ bỏ, Vương Lâm nâng ngón út thi triển sát chiêu cuối Hoàng tuyền chỉ của Tư Đồ Nam: tiêu tan sinh mạng, trời tối sầm sét đánh, hiện tranh sơn thủy biểu thị Hoàng tuyền cùng Sinh tử luân hồi ý cảnh. Thiên Vận Tử ngưng trọng nhìn kỹ, Kiếm Tôn Lăng Thiên Hầu thầm khen, còn một lão già mặt đỏ mang hồ lô đỏ giật mình nhận ra sát chiêu này giống hệt của một “người điên” lão từng gặp, khi mọi ánh mắt đổ dồn về Vương Lâm."},{"chuong":472,"tieuDe":"Toái Tiên Chi Địa","tomTat":"Vương Lâm phóng hai đạo Hoàng tuyền chỉ công kích Trần Đào nhưng đối phương nhờ kỳ ngộ đạt Vấn Đỉnh trung kỳ nên đỡ được; Vương Lâm bị đẩy lùi, phun tiên huyết và bỏ cuộc, để Trần Đào đoạt phong hiệu Thiên Vận Thất tử của Tử hệ. Thiên Vận Tử trao tinh thể phong hiệu cho Trần Đào, kết thúc đại thọ vạn năm tuổi; Kiếm Tôn Lăng Thiên Hầu rời đi và nhắc ước hẹn ba tháng sau phải tuyển người vào Đông Hải Yêu Linh chi môn. Thiên Vận Tử nhận Vương Lâm làm đệ tử chân chính, hứa truyền Cấm pháp thần thông cùng pháp bảo bản mạng, đưa về Tổng tông ba ngọn núi tại Thiên Vận Tinh. Vương Lâm giải đúng câu đố rằng hai sườn núi hai bên là giả do Chân huyễn pháp, nên được đặc ân tự chọn Cấm pháp thần thông; cảnh ba ngọn núi gợi hắn nhớ ký ức Cổ Thần Đồ Ti về thanh tam xoa kích hóa cự sơn. Theo khảo nghiệm, hắn leo ngọn núi trắng phủ Cửu U chi hàn không dùng thuấn di, đến gần đỉnh trăm bước thì hạ chân xuống băng và bước vào Toái Tiên chi địa. Nơi đây hắn lĩnh ngộ Vấn Tâm chỉ cảnh — tâm lạnh hơn vạn vật băng hàn, ý chí bất khuất bao thân — và nhận ra Luân hồi đạo chính là đại Vô tình đạo, hiện Luân hồi Hoạ trục sau lưng. Vượt cực hạn Anh Biến trung kỳ, Vương Lâm đi hai mươi mốt bước khiến Thiên Vận Tử khiếp sợ, rồi tiếp tục bước thứ hai mươi hai và thêm năm bước nữa, tiến gần kỷ lục hai mươi sáu bước của Tôn Vân."},{"chuong":473,"tieuDe":"Ý Cảnh Nhập Thể!","tomTat":"Trên nền hai mươi bước, Vương Lâm dung một tia cảm ngộ vào tâm cảnh, bước thêm năm bước đạt cực hạn hai mươi bảy bước; Luân hồi Họa trục bộc phát khí thế kinh người, ý cảnh bắt đầu thực chất hóa và mở ra con đường lên Vấn Đỉnh. Sinh Tử Luân Hồi đạo của hắn là loại lĩnh ngộ cực hiếm khó thực chất hóa nhất, nhờ kết hợp Vấn Tâm chi đạo tại Toái Tiên chi địa mới khai thông; bước thứ hai mươi tám nếu bước ra sẽ khiến tu vi sụp đổ. Thiên Vận Tử dự đoán trong vòng trăm năm Vương Lâm có hy vọng Vấn Đỉnh, dùng ánh sáng bảy màu tạo cầu vồng đưa hắn tới dưới bảo tháp và kể nguồn gốc Thiên Vận Tông theo đuổi Thiên vận số. Lão xé không trung tỏa ánh sáng Tối hỉ thất thải chiếu rọi gần nửa bầu trời Thiên Vận Tinh, rồi chính thức thu Vương Lâm làm đệ tử thứ bảy của Tử hệ. Vương Lâm quỳ bái, thề chỉ cần sư phụ và Thiên Vận Tông không phụ hắn thì hắn không phụ lại; Tế đàn bảy màu hạ xuống, lệnh bài khắc danh tự cháy hóa lửa tím. Cuối chương, Thiên Vận Tử hỏi Vương Lâm muốn chọn loại Cấm pháp thần thông nào, hắn trầm ngâm vì đã có nhiều pháp công kích như ba thức sát chiêu của Tư Đồ Nam, Xạ Thần xa, kiếm tiên và loan đao."},{"chuong":474,"tieuDe":"Hơn Một Người!","tomTat":"Vương Lâm cân nhắc thần thông phòng thân và nhận ra Cấm pháp Đại Na Di cùng Ngân Long la bàn chỉ đủ đối phó tu sĩ Vấn Đỉnh, không kham được kẻ đạt cảnh giới Toái Niết. Hắn xin Thiên Vận Tử truyền ‘Sinh tồn pháp thuật’ nhưng bị từ chối, nên được sư phụ điểm ánh sáng bảy màu đưa vào thế giới bảy màu chứa 3600 đạo Cấm pháp thần thông để tự chọn. Quan khán hơn phân nửa, hắn ghi nhận Cửu chuyển luyện tiên quyết, Cấm pháp Tiên Ma thể và thần thông bảy màu (Tối hỷ khẩu thất thải) — chỉ thứ cuối khiến hắn khiếp sợ và gần như định chọn. Bất ngờ hắn chú ý một Thiên Vận Tử mặc áo bào màu tro, mắt xám, trẻ hơn và không có tiên lực; mọi công kích bằng Cấm chế ấn quyết, kiếm tiên và loan đao đều xuyên qua thân như ảo ảnh. Khi sát khí người áo xám lan ra, cả 3600 Thiên Vận Tử hô ‘Phong!’ dựng phong ấn nhưng bị một chữ ‘Cút!’ làm sụp đổ, đẩy lui mấy vạn dặm — thần thức Vương Lâm đếm ra tổng cộng 3601, ‘hơn một người’. Sau sáu lần chạm mặt, người áo xám tiết lộ Thiên Vận Tử đưa hắn tới chính vì Sát Lục Tiên quyết, một thứ bắt chước Tiên thuật vô danh dựa vào giết chóc đoạt sinh lực, với điều kiện ‘không lưu người sống’. Vương Lâm thi triển Sinh tử Luân hồi ý cảnh rồi trầm mặc từ chối ‘Ta không học!’; người áo xám không đáp câu hỏi về quan hệ với sư phụ mà hoá một ngọc giản từ bụi khí để lại, và Vương Lâm bắt lấy, ánh mắt trầm ngâm."},{"chuong":476,"tieuDe":"Huyền Uyên Phái","tomTat":"Vương Lâm bước vào Truyền tống trận khổng lồ phạm vi mười dặm của Huyền Uyên Phái; tu sĩ Triệu Tứ kết quyết đánh một đạo thanh quang vào trận, toàn trận chấn động và truyền Vương Lâm vượt liên tinh cầu rời Thiên Vận Tinh tới Địa Tinh. Triệu Tứ ở lại hâm mộ nhìn theo, thắc mắc Thất sư tổ tới Địa Tinh làm gì rồi chuyên tâm tu luyện hướng Hoá Thần hậu kỳ. Địa Tinh là một trong năm tinh cầu phụ quay quanh Thiên Vận Tinh, nơi có Huyền Uyên Phái — Lục cấp tu chân quốc duy nhất do Lão Tổ Huyền Minh đứng đầu. Thiếu Tông Hứa Vân Sơn cầm bảo phiến ngọc bích cùng các Trưởng lão ra Truyền tống trận nghênh đón, vì sớm biết sứ giả mới là Tử hệ Lão Thất Vương Lâm nên rung động muốn kết giao. Vương Lâm hiện thân, thấy Hứa Vân Sơn cũng là Anh Biến Trung kỳ nên thuận theo, được thu xếp chỗ u tĩnh. Trong hoa viên, hắn ngẫm về việc đề cao tu vi để đối phó Thác Lâm, về Sát lục tiên quyết, Sinh chi lạc ấn và Thiên nghịch châu còn thiếu kim thuộc tính. Sau hai ngày, Hứa Vân Sơn đưa hắn tới Ngũ cấp tu chân quốc Linh Nhạc quốc để nhận chức sứ giả, nơi có toà tháp chọc trời làm chỗ ở của các thế hệ sứ giả."},{"chuong":477,"tieuDe":"Sứ Giả","tomTat":"Vương Lâm chính thức nhậm chức Sứ giả của Huyền Uyên Phái tại Linh Nhạc quốc, được hơn trăm tu sĩ cung kính đón tiếp; Hứa Vân Sơn cáo từ rời đi, để mình hắn tọa trấn Thông Thiên tháp. Hắn tuyên bố bế quan, cấm mọi người bước vào phạm vi ngàn dặm, dùng Cấm Phiên phóng hắc khí tạo màn sương đen và thả các Chủ hồn từ Tôn Hồn Phiên ra phòng bị, rồi nghiên cứu Sát Lục Tiên quyết — một đạo Sinh chi lạc ấn dựa vào giết chóc mà sinh ra. Suốt hơn một tháng hắn không tìm được điểm khởi đầu nên chuyển sang lĩnh ngộ thiên đạo; cùng lúc Xạ Thần xa cắn trả lần đầu kể từ khi giải khai đạo phong ấn, hắn đại chiến Khuất thú mấy ngày rồi dùng bí pháp áp chế thành công. Thiên Thai lão nhân, cao thủ đệ nhất Linh Nhạc quốc, đến tháp thăm dò, tận mắt thấy Khuất thú nên khiếp sợ, khiến các tông phái hạ lệnh lập cấm địa quanh tháp. Cuối cùng Vương Lâm ngộ ra Sát Lục Tiên quyết phải cảm ngộ từ giết chóc thật, bèn thu hết màn sương đen ngưng thành Cấm Phiên tím đen và thu Chủ hồn tế luyện. Nhớ lời sư phụ dặn đến Đông Hải trong ba tháng, hắn lên đường, trước hết tới Ngũ Linh Sơn gặp Thiên Thai lão nhân."},{"chuong":478,"tieuDe":"Địa Ma Bắc Giới","tomTat":"Thiên Thai lão nhân tự trách vì để lão đạo phá quy củ kinh động Khuất thú khiến Vương Lâm không thu phục được con thú, rồi trao cho hắn ngọc giản ghi ba chỗ yêu thú tụ tập trên Địa Tinh; lão nhận ra giữa mi tâm Vương Lâm ẩn sát khí và đoán hắn đi vì giết chóc. Vương Lâm thi triển pháp thuật thuấn di ngân mang, bước mười bước cực hạn tạo dị tượng mặt trời bạc để tới Cực Bắc Địa Tinh, hiện thân tái nhợt phải dùng đan dược hồi phục. Hắn hoá tử hồng bay tới trước tấm bia đá khắc bốn chữ đỏ Địa Ma Bắc Giới, tuyên bố sẽ tu Sát Lục Tiên quyết tại đây vì công pháp phải ở trong giết chóc mới lĩnh ngộ, rồi bước thẳng vào làn sương mù. Ngay sau đó nhóm năm người Đại La Kiếm Tông do đại sư huynh Quách Tà Dật dẫn đầu bay đến chân bia, chờ Sư bá. Quách Tà Dật mâu thuẫn với Thiên Cầm cô nương vì mượn danh sư môn chiếm Diệu Kim quả, chỉ hứa để lại cho nàng một quả. Cuối chương ba Trưởng lão Đại La Kiếm Tông giáng lâm gồm một lão Hoá Thần hậu kỳ là sư thúc và hai Kiếm Các Trưởng lão Anh Biến sơ kỳ, được Quách Tà Dật quỳ tham kiến; trong sương mù Vương Lâm để tâm tới Đại La Kiếm Tông nhằm tìm tung tích Chu Dật tiền bối và tò mò về Diệu Kim quả."},{"chuong":479,"tieuDe":"Văn Thú Tiến Hoá!","tomTat":"Hai lão già Anh Biến sơ kỳ — Trưởng lão Đại La Kiếm Tông — tra hỏi Quách Tà Dật về Diệu Kim quả; hắn chỉ về phía Thiên Cầm, khai rằng sư môn nàng phát hiện vật nhưng có yêu thú thủ hộ nên không lấy được. Nghe Thiên Cầm đáp ước chừng trăm quả, lão già thấp người mắt bừng tinh quang; đồng môn nàng tức giận trách Đại La Kiếm Tông liền bị nàng quát im. Quách Tà Dật xin cho nàng một quả, lão già cao người đồng ý và bảo dẫn đường; Thiên Cầm chua xót hận hắn phản bội nhưng vì khí tức hai Trưởng lão vượt xa sư môn nhỏ bé của mình nên đành cắn răng dẫn đoàn vào Địa Ma Bắc Giới. Trong khi đó, Vương Lâm phi hành trong Tùng Mãng Sơn mạch tu luyện Sát Lục Tiên quyết, giết tiểu thú sương đen và Bôn Ngưu thú để thu bụi khí nghi là sinh lực, đồng thời thả Văn thú hấp thu nội đan, huyết nhục các yêu thú Hóa Thần để nuôi nó lớn lên. Văn thú — thú đến từ tinh không, càng ăn càng mạnh — lóe bạch mang mỗi lần nuốt, đang ở thời khắc mấu chốt sắp tiến hóa, khiến Vương Lâm thấy hình ảnh một tinh cầu đầy Văn thú vô tận. Cuối cùng hắn phát hiện vị trí Diệu Kim quả ở phía Nam, cưỡi Văn thú bay nhanh tới, dự định dùng hai lão Anh Biến sơ kỳ làm thí luyện giả cho công pháp của mình."},{"chuong":480,"tieuDe":"Cửu Lê Trùng","tomTat":"Đoàn Đại La Kiếm Tông gồm hai Trưởng lão Anh Biến sơ kỳ là Thạch Phương và lão già thấp người, một lão già Hoá Thần kỳ (sư bá Quách Tà Dật) cùng Thiên Cầm dẫn đường, tiến sâu vào Địa Ma Bắc Giới tìm Diệu Kim quả. Càng vào sâu, một cỗ áp lực quỷ dị như vạn sơn áp đỉnh bao phủ, ánh mắt vô hình theo dõi khiến hai Trưởng lão khó thở và sinh ý giết người, song thần thức dò xét không thu hoạch gì. Vương Lâm ngồi trên Văn thú vô thanh vô tức bám theo phía sau, dựa ký ức Cổ Thần Đồ Ti nhận ra Diệu Kim quả thực chất là kim linh căn — vật khiến thân thể cứng rắn, thuốc bổ hiếm có với Cổ Thần thuở nhỏ và có tác dụng đặc thù với Văn thú đang loé bạch mang khát vọng. Thiên Cầm chỉ tới sơn cốc, Thạch Phương ngưng côn tiên lực hoá tiên phong thổi tan cây cối, mở thông đạo lộ ra phiến hoa vàng cùng đám Diệu Kim quả nhỏ như đầu ngón tay. Hai Trưởng lão phát hiện ổ Cửu Lê trùng ẩn dưới lá khô gần đó làm mãnh thú thủ hộ, cần dược dẫn để đối phó. Lão già thấp người tàn nhẫn dùng lực vô hình ném gã đồng môn áo trắng bên Thiên Cầm vào sơn cốc làm mồi, lập tức vô số điểm đỏ Cửu Lê trùng như tia chớp dày đặc lao ra cực kỳ đáng sợ."},{"chuong":481,"tieuDe":"Vỡ!","tomTat":"Nam tử áo trắng — sư huynh của Thiên Cầm — bị ném vào giữa sơn cốc và bị vô số Cửu Lê trùng chui vào da thịt ăn thịt, dãy dụa thảm thiết rồi tắt tiếng trong tuyệt vọng. Thiên Cầm chấn động gặng hỏi tiền bối vì sao, từ thê thảm chuyển sang bình tĩnh đáng sợ, trong khi Quách Tà Dật thừa nhận đã dựng nên việc này và kết thù với nàng. Thạch Phương, Trưởng lão Đại La Kiếm Tông, dùng cấm thuật Kiếm phong chi cấm qua ngọc giản đỏ hóa lưới tơ kết kỳ hiệu điện quang phong ấn đàn trùng; cùng lão già lùn dọn sạch số Cửu Lê trùng còn sót để mở đường vào cốc. Lão già lùn sai Lữ Tùng Nghĩa — lão già Hóa Thần kỳ, sư thúc Quách Tà Dật — đi hái Diệu Kim quả trên tảng đá vàng. Đột nhiên một cơn gió mát khiến hai Trưởng lão đại biến sắc mặt, cảm giác đè nén từ khi vào Địa Ma Bắc giới bùng nổ, một đoàn bụi khí nồng đậm xuất hiện ngoài cốc. Lão già lùn ném gương đồng tỏa thanh quang và Thạch Phương hóa bóng kiếm hơn mười trượng chém xuống, còn Lữ Tùng Nghĩa lao tới bên Diệu Kim quả. Bụi khí bùng lên như vạn mã phá tan tất cả, giọng lạnh lẽo vang lên rằng ánh sáng đom đóm sao sánh được ánh trăng, khiến gương đồng vỡ vụn và kiếm của Thạch Phương tan biến."},{"chuong":483,"tieuDe":"Giết!","tomTat":"Vương Lâm vỗ túi trữ vật, kiếm tiên nhốt Hứa Lập Quốc cùng thanh loan đao truy đuổi giam giữ lão già thấp người Trưởng lão Đại La Kiếm Tông đang bỏ chạy. Đối mặt kiếm quang và nguyên thần ly thể của Thạch Phương, hắn dùng kính tản tia sáng phát Tứ chuyển hàm tiên lực vỗ tan kiếm quang làm nứt vỡ sơn cốc, rồi thả tiên ảnh đánh trọng thương nguyên thần và sai Văn thú nuốt sạch thân xác Thạch Phương chỉ chừa hài cốt. Thạch Phương vội đoạt xá tiểu bối Quách Tà Dật theo lối siêu tốc khiến Vương Lâm kinh ngạc, rồi cầu xin tha mạng, giết hai tiểu bối để tỏ thành ý và hiến ngọc giản đoạt xá kèm thần thông mượn xử nữ chữa thương. Thiên Cầm run rẩy quỳ cầu Vương Lâm giết Thạch Phương cùng Trưởng lão Đại La Kiếm Tông, nguyện làm trâu ngựa hầu hạ. Vương Lâm dò hỏi vụ kiếm hồn và Kiếm Tôn Lăng Thiên Hậu hai trăm năm trước nhưng nhận ra Thạch Phương không nói thật, nên sau khi nhận ngọc giản đã phóng khí xám khiến thân Thạch Phương nổ tung, để lại một khối cầu xám. Cuối cùng hắn tới mảng hoa vàng phía Tây hái một Diệu Kim quả, dự định bổ kim thuộc tính cho Nghịch Thiên châu vốn còn thiếu gần một nửa sau trận Chu Tước mộ, chưa lập tức tra hỏi Trưởng lão Đại La Kiếm Tông đang bị giam."},{"chuong":484,"tieuDe":"Kim Linh","tomTat":"Vương Lâm đặt Diệu Kim quả lên mi tâm nhưng thất vọng khi nhận ra nó khó làm viên mãn kim thuộc tính của Nghịch Thiên châu, nên cho Văn thú hút một phần ba số quả. Theo ký ức Đồ Ti, hắn bố trí ngọc giản khắc văn, kết thủ ấn cổ quái và thốt Chú ngôn ‘Một!’, phóng ánh sáng vàng làm nổ từng ngọc giản, ép hoa, quả và cành cây héo rũ tan thành chất lỏng vàng dung nhập xuống đất. Sau nửa nén hương, hắn bới đất thu được bốn kim linh căn cỡ ngón tay cái giống nhân sâm, hiểu rằng nếu hình thành tự nhiên hẳn đạt năm chiếc. Thiên Cầm đứng xem từ chỗ đau lòng vì quả héo rũ đến vỡ lẽ giá trị thật của Diệu Kim quả nằm ở gốc rễ. Vương Lâm ném một rễ cho Văn thú khiến nó bắt đầu biến hoá và bị kim quang bọc thành lồng vàng, một rễ cho Lôi Oa, rồi tặng Thiên Cầm sợi cuối coi như đền cơ duyên, thu thân cây lưu cho bổn tôn. Hắn hoá khói rời đi, phóng vào chỗ sâu Địa Ma Bắc giới. Ở nơi khác, Trưởng lão Đại La Kiếm Tông mặt tái nhợt ngồi trên đại thụ, bị một thanh loan đao chĩa mi tâm và một kiếm tiên chĩa thiên linh cái uy hiếp, không dám cử động."},{"chuong":485,"tieuDe":"Mục Tiêu - Đông Hải!","tomTat":"Vương Lâm khống chế lão già thấp người của Đại La Kiếm Tông bằng phi kiếm cực cứng và thanh loan đao quỷ dị dán chặt mi tâm, ép lão khai mọi điều. Lão khai chuyện Kiếm Tôn từ tiên giới trở về bị một đạo kiếm hồn truy kích, cuối cùng phong ấn hơn 1/3 kiếm hồn cùng Chu Dật ở chỗ sâu trong Đông Hải Yêu Linh chi môn — một trong ba đại cấm địa bên ngoài Thiên Vận tinh, nơi huyết tinh thí luyện mở mỗi năm ngàn năm, với phần thưởng Yêu Linh quán đính có thể tăng một cảnh giới và hỗ trợ đột phá Vấn Đỉnh, Âm Dương nhị ý. Khai xong, qua cảm ứng của Hứa Lập Quốc, loan đao xuyên đầu giết lão; lão dùng Tam phân thần thức thuật tái sinh lần cuối và thề báo thù, nhưng vừa bay đi liền bị hai làn khí xám Sát lục tiên quyết của Vương Lâm xuyên thân hút sạch sức sống mà chết thật. Vương Lâm tự nhủ ba lý do đi Đông Hải: tu Sát lục tiên quyết, cứu ân nhân Chu Dật, và tuân lệnh sư phụ Thiên Vận Tử, đồng thời mong tìm kim thuộc tính giúp Nghịch Thiên châu viên mãn để Lý Mộ Uyển thức tỉnh. Hắn ẩn trong Địa Ma Bắc giới hai mươi ngày, ngưng kết Sinh ấn ba phân khiến thân thể cứng hoá kiếm chỉ không xuyên thấu, rồi hướng ánh mắt quyết đoán về phía Đông Hải."},{"chuong":486,"tieuDe":"Vì Sao Đông Hải","tomTat":"Chương giới thiệu Đông Hải Yêu Linh — nơi thần bí phía đông Thiên Vận Tinh trông như mặt biển hai màu xanh đỏ, cứ năm nghìn năm bập bênh một lần phát ra lực lượng kỳ dị hút mọi vật vào trong mà không phóng thích, được đồn là tiên phủ của một tiên quân hoặc không gian thông đạo trên cả tiên giới. Xưa kia Thiên Vận Tử cùng Kiếm Tôn Lăng Thiên Hậu lập nhóm thăm dò ba lần, lần thứ ba ra chỉ còn nửa quân số rồi hai người tách nhau, giữ kín bí mật; Thiên Vận Tử tuyên bố trong đó có Cổ Yêu và lập nơi này thành cấm địa, Tu Chân Liên Minh đành để mặc. Cứ năm nghìn năm cửa mở một lần là đại sự bậc nhất, các lão quái phái đệ tử Anh Biến đến Hư Thực Nhị Ý vào, nhưng cấm tu vi vượt Vấn Đỉnh và cửa chỉ mở một nửa. Còn năm ngày trước khi mở, vô số tu sĩ tụ về hư không; rồi hồng quang và mùi máu tanh báo hiệu Diêu Tích Tuyết — con gái Huyết Tổ Diêu Tinh Hải — cưỡi huyết ngọc khổng lồ đến, nhắm mắt khoanh chân ngồi chờ. Chương kể lai lịch Huyết Tổ: lão quái thông thiên từng bảy lần khiêu chiến Thiên Vận Tử, độc chiếm Huyết Tinh nạp huyết tu ma công, truyền toàn bộ công pháp cho con gái. Tại truyền tống trận Huyền Uyên phái trên một phó tinh, thiếu tông chủ Tôn Vân Sơn ngăn em gái áo hồng đòi lên Đông Hải, sai Huyền Nhất bắt nàng về dù nàng viện cớ “Mẹ đã đồng ý rồi”. Cuối cùng Tôn Vân Sơn phát hiện người đến qua truyền tống trận, mỉm cười nói “Vương huynh! Tôn mỗ chờ huynh đã lâu!”."},{"chuong":487,"tieuDe":"Hành Trình Của Tham Lang","tomTat":"Vương Lâm hóa đạo cầu vồng tử quang phóng tới hội hợp với Tôn Vân Sơn, người vốn cố đợi hắn để cùng đi Đông Hải Yêu Linh dù bị gia phụ ép buộc. Tôn Vân Sơn giới thiệu xá muội Tôn Nhược Nam và ba trưởng lão Huyền Uyên phái, rồi ra lệnh mở trận pháp tinh không tạo cầu vồng cao trăm trượng đâm vào tầng mây, nhưng từ chối cho Tôn Nhược Nam đi theo; nàng bèn lén dùng truyền tống ngọc giản trộm của cha hóa sợi tơ trắng bám theo. Ở cửa Đông Hải Yêu Linh phía đông ngoài Thiên Vận Tinh, hơn một vạn tu sĩ và nhiều lão quái tụ tập chờ hiện tượng thủy triều năm nghìn năm một lần, trong đó con gái Huyết Tổ Diêu Tích Tuyết được kiêng nể. Kiếm Tôn Lăng Thiên Hậu xuất hiện, cưỡi Hùng Lân thú dẫn theo Kiếm Tiếu Thập Nhị Tử, được tiết lộ là kình địch cả đời của Thiên Vận Tử. Mục đích thật của lão là mượn thủy triều để hút đạo kiếm hồn của một nữ quân tiên giới chìm sâu vĩnh viễn vào Đông Hải, quyết không để rơi vào tay Thiên Vận lão tặc. Ngay lúc đó Tham Lang cưỡi đống xương khô khổng lồ phá hư không xông vào, chào Lăng Thiên lão hữu, thân mang thương nặng vì phải tránh Tư Đồ Nam, và đề nghị tặng Kiếm Tôn một cơ duyên cực lớn để đè đầu Thiên Vận Tử."},{"chuong":488,"tieuDe":"Tâm Tư Của Tham Lang","tomTat":"Kiếm Tôn Lăng Thiên Hậu dò hỏi vì sao Tham Lang để ý một vật, Tham Lang tiết lộ chuyện mấy vạn năm trước Tu Chân Liên Minh treo thưởng một bộ thượng phẩm tiên thuật hoàn chỉnh để tìm một hạt châu, thừa nhận vết thương của mình liên quan đến hạt châu và đang bị người giữ nó bức bách. Lăng Thiên Hậu hoãn việc đến sau Đông Hải Yêu Linh, đổi lại yêu cầu Tham Lang vào trong bảo vệ mười hai đệ tử của lão hoàn thành nhiệm vụ bí mật, vạch trần tâm cơ Tham Lang và hứa mở cửa Yêu Linh cho hắn. Thiên Vận Tử mặc áo trắng từ đám mây bảy màu bước ra, dẫn chín đệ tử Thiên Vận Tông (gồm lão lục Trần Đào) tới cửa Đông Hải và được nghênh đón long trọng nhất; lão cùng Trần Đào tìm kiếm Vương Lâm. Vương Lâm hóa thân ảnh tử sắc phóng tới, tách khỏi Tôn Vân Sơn rồi cung kính bái kiến sư tôn, được nhận ra là Tử Hệ Lão Thất và đứng vào hàng chín đồng môn dưới ánh mắt thâm ý của Thiên Vận Tử. Lăng Thiên Hậu thấy hắn quen mặt, Tham Lang cảm thấy hắn như cố nhân năm xưa, còn Diêu Tích Tuyết theo lời phụ thân dò xét tên đệ tử mới. Thủy triều Đông Hải bắt đầu khởi động với tiếng nổ ầm ầm, hơn một vạn tu sĩ chấn động khi ngày hoàng kim năm nghìn năm một lần chỉ còn cách một ngày."},{"chuong":489,"tieuDe":"Thủy Triều","tomTat":"Tại cửa Đông Hải Yêu Linh — một trong tam đại cấm địa phía đông Thiên Vận Tinh — hiện tượng thủy triều năm nghìn năm một lần khởi động: mặt biển bập bềnh như nham thạch sắp phun, vô số vật trôi nổi giãy dụa giữa tiếng nổ ngập trời. Vương Lâm lần đầu chứng kiến nơi này, chỉ biết về nó qua lời Tôn Vân Sơn kể trên đường. Các vật trôi nổi chậm rãi xoay tròn dưới một lực kỳ dị, hút những tu sĩ tu vi yếu về phía vòng xoáy, nhưng đạo tâm Vương Lâm vẫn kiên định. Thanh khí xanh bốc lên ngưng tụ về trung tâm thành cột cao trên ngàn trượng giống mắt quỷ, tản ra cổ uy áp nồng hơn thiên uy gấp bội khiến Vương Lâm phải dùng đạo khí xám mi tâm hóa ký hiệu bao thân mới chống đỡ tới cực hạn, nhiều tu sĩ mặt trắng rút lui suýt chết. Lăng Thiên Hậu lẩm bẩm “Bắt đầu rồi!”, còn Thiên Vận Tử băn khoăn lần này vật gì sẽ bị hút đến. Cột thanh khí nổ tan, hồng quang đỏ chói tản ra vô tận bao phủ Đông Hải Yêu Linh, lan tới các tinh cầu hoang và tận Chu Tước Tinh khiến Chu Vũ Thái đang tĩnh tọa bừng mở mắt. Hồng quang dừng ở cực hạn, mọi vật vô chủ trong phạm vi — pháp bảo, ngọc giản, linh thạch, tiên ngọc, thi hài, cổ kiếm, tàn bảo, tiên quyết — đồng loạt rung động."},{"chuong":490,"tieuDe":"Lệnh Bài","tomTat":"Cửa Đông Hải Yêu Linh bên ngoài Thiên Vận Tinh mở ra, luồng hồng quang nghìn năm mới hiện một lần đột ngột ngừng rồi điên cuồng rút về như thủy triều, cuốn theo vô số pháp bảo, linh thạch, ngọc giản, tiên ngọc, yêu thú và linh vật vô chủ về cửa, làm tinh không vang tiếng nổ ầm. Vương Lâm kinh hoàng chứng kiến cảnh tượng hồng quang xuyên thấu thân thể tu sĩ như ảo giác, và nhờ ký ức Cổ Thần Đồ Ti nhận ra nhiều vật luyện khí quý như Thiên Kim Thượng, Quỳnh Hoa Dịch, Thủy Mặc Thạch, Linh Tê Giác cùng một thanh đại kiếm rỉ sét hình cánh cửa loé lên rồi biến mất. Con sóng hồng quang cuối quỷ dị ngăn cản thần thức khiến nhiều tu sĩ chạm vào liền sụp đổ, phun máu; một lão già gầy đét cảnh báo đừng dùng thần thức xem. Vương Lâm vận ba đạo ấn ký khí xám trên mi tâm thành thần thông ánh mắt, chịu đau chảy máu mắt, cuối cùng ánh mắt nổ tung phá vỡ hồng quang và nhìn rõ một khối lệnh bài kim quang khắc ký hiệu, khiến Thiên Vận Tử, Kiếm Tôn Lăng Thiên Hậu cùng các lão quái Thiên Vận Tinh đại biến sắc lao ra tranh đoạt. Sau đó, Diêu Tích Tuyết ngồi trên huyết ngọc phương xa vô ý nhìn thấy ánh mắt yêu dị mang khí xám của Vương Lâm liền chấn động, mặt tái nhợt vội cúi đầu, hiểu ra vì sao phụ thân dặn nàng phải chú ý đến người này."},{"chuong":491,"tieuDe":"Đông Hải Yêu Linh","tomTat":"Kiếm tôn Lăng Thiên Hậu chỉ tay về Đông Hải, bốn kiếm ảnh hóa cầu vồng đánh vào khối nước khổng lồ lơ lửng, mở ra lối vào hỗn độn xanh đỏ dẫn tới một thế giới khác. Kiếm Tiếu Thập Nhị Tử của Đại La kiếm tông vào trước, đệ tử cuối được ban kiếm khí bảo mệnh — chính là Tham Lang đã hóa thành; mười người Thiên Vận Tông gồm Vương Lâm cùng khoảng cả trăm tu sĩ nối nhau vào, Diêu Tích Tuyết hóa huyết quang bay theo. Lăng Thiên Hậu thu kiếm đóng cửa; Thiên Vận Tử xác nhận có ba lệnh bài liên quan đại bí mật Thiên Vận Tinh, ước định năm trăm năm sau tụ lại tiến vào lần nữa. Lăng Thiên Hậu về Đại La tinh bế quan, quyết hai trăm năm lấy chín chín yêu linh quy nhất luyện Tiên kiếm thành yêu kiếm; Thiên Vận Tử về bảo tháp bảy màu rải xương thú tà dị bói vận may Vương Lâm. Bên trong cánh cửa, Vương Lâm bị lực kỳ dị đẩy tản vào hoang nguyên một mình. Hắn lập kế hoạch năm trăm năm: tu Sát lục tiên quyết tới đại thành, tìm cứu Chu Dật, truy tìm Cự Phú học kiếm kỹ kiếm hồn, tất cả để đề phòng Thác Sâm thoát khốn truy sát."},{"chuong":492,"tieuDe":"Sơn Cốc","tomTat":"Vương Lâm trầm tư về khối lệnh bài bí ẩn trên Thiên Vận Tinh từng khiến Thiên Vận Tử và Lăng Thiên Hậu biến sắc, định mượn năm trăm năm ẩn náu ở tinh cầu để tăng nhanh tu vi và tránh Thác Sâm. Bay mười ngày qua bình nguyên hoang vu vắng lặng, hắn đột nhiên biến sắc rồi thuấn di tới một vùng núi non trùng điệp. Tại đó hắn chứng kiến một người nửa xích lõa, vẽ nhựa cây ẩn thân, không có linh lực nhưng linh tính kinh người, dùng dao u quang giết chết một con dã thú không linh lực mà máu lộ u quang. Vương Lâm hiện thân, người nọ cảnh giác giành con thú; hắn cười nhường rồi lặng lẽ theo dõi, thấy người này kéo thú vào một sơn cốc. Quan sát kỹ, Vương Lâm kết luận bên ngoài cốc có trận pháp ẩn giấu khí tức sinh mạng do tu sĩ thượng cổ bố trí, thủ pháp khác hẳn liên minh tu chân và khó phá giải trong thời gian ngắn. Hắn thử phóng linh quang dò trận thì bị luồng khí xanh thôn phệ phản kích, theo sát cũng bị cản lại. Cuối cùng hắn làm tan trường côn của một người mới xông ra, dùng lực vô hình giam bốn người để tra hỏi nguồn gốc nơi này, rồi hai người nữa từ trong cốc tiếp tục đi ra."},{"chuong":493,"tieuDe":"Trưởng Lão Trong Cốc","tomTat":"Hai sinh vật rời sơn cốc cắn lưỡi phun máu tạo nên huyết vụ đỏ dày đặc, từ đó một bóng đen ẩn hiện đòi Vương Lâm trả người và cút khỏi bộ tộc. Vương Lâm bước một bước sinh sóng không khí ầm ầm, làm tan huyết vụ trong chưa tới ba nhịp thở rồi bắt giữ kẻ hắc bào ném vào chỗ sáu người còn lại. Sau ba ngày, lão giả tóc bạc Âu Dương Hoa cầm quải trượng đen cùng mười một sinh vật thân trâu mình người bước ra, tự xưng trưởng lão sơn cốc, xin thả tộc nhân để đối thoại. Lão tiết lộ về Cổ yêu thành ngoài ba ngàn dặm, khuyên Vương Lâm tới đó tìm vật cần và nói người ngoài cứ bốn trăm năm lại tới một lần gây gió tanh mưa máu. Vương Lâm lấy Cấm Phiên phóng chín trăm chín mươi chín đạo cấm khí đen công phá trận, đồng thời nhận ra Âu Dương Hoa trước mặt chỉ là thế thân hư ảo. Trận pháp phản kích, hút kéo vạn vật ngưng thành hư ảnh người màu xanh cao mấy trượng để giết Vương Lâm lấy hồn phách tế yêu linh. Vương Lâm triển khai Cấm pháp chi mâu, ngưng cấm khí đen thành trường mâu ba trượng rồi vung hóa tia chớp đen lao thẳng vào hư ảnh xanh."},{"chuong":494,"tieuDe":"Phá Trận","tomTat":"Vương Lâm dùng trường mâu cấm khí phá không lao tới đánh tan thanh ảnh xanh của trận pháp thượng cổ, thì thanh ảnh bất ngờ bắt quyết đọc khẩu quyết như tu sĩ, kích hoạt lồng thanh quang phạm vi ngàn trượng vây giam hắn. Trong lúc lùi lại, Vương Lâm vận thượng cổ cấm chế của cổ thần để tính toán, ghép phù văn thành các tổ hợp cấm chế, đếm dần từ năm mươi bảy lên. Âu Dương Hoa từ trong sơn cốc cười lạnh chiêu hàng tàn nhẫn, đòi hắn tự cắt một tay một chân để hấp thu nguyên thần, còn dọa biến hắn thành yêu ảnh thứ hai. Thanh mang thôn phệ vạn vật thu nhanh, sinh vật đi qua héo rũ, ép tới chỉ còn cách ba trượng. Vương Lâm phản kích bằng phù văn cấm chế leo thang từ một đạo đến tổng cộng tám mươi ba tổ hợp, đánh tan thanh võng và cột sáng xanh. Hắn từng bước áp sát sơn cốc, lực lượng bảo vệ tiêu tán hoàn toàn, khiến Âu Dương Hoa hoảng sợ cầu xin tha mạng và thừa nhận biết sai."},{"chuong":495,"tieuDe":"Hoàng Long","tomTat":"Âu Dương Hoa dẫn mười tộc nhân ra khỏi sơn cốc, cung kính xưng Vương Lâm là thượng tiên và khẩn cầu hắn đừng phá trận pháp kẻo cả tộc bại lộ dưới yêu linh. Vương Lâm giơ tay điểm lên hư không, khôi phục trận pháp cổ làm tốc độ tiêu tán của lực lượng bảo vệ ngừng hẳn. Âu Dương Hoa vẩy giọt máu mở thông đạo mời vào cốc; Vương Lâm phát hiện cả sơn cốc đều là phàm nhân, cảm thấy xấu hổ nên ôm quyền tạ lỗi, ném ba bình ngọc đan dược cố bổn bồi nguyên rồi định rời đi. Âu Dương Hoa cảnh báo tối nay là đêm yêu linh, pháp lực thông thiên cũng khó chống nổi nên mời Vương Lâm về nhà mình. Tại đó Vương Lâm thấy bức tranh ố vàng vẽ Hoàng Long thượng tiên, người vô số năm trước dẫn tổ tiên Âu Dương Hoa đến định cư. Cái tên Hoàng Long khiến nguyên thần Vương Lâm chấn động, tâm thần hắn hồi tưởng quê nhà Chu Tước tinh và thời thiếu niên từ sơn thôn đi ra gia nhập Hằng Nhạc phái."},{"chuong":496,"tieuDe":"Thiên Yêu Quận","tomTat":"Vương Lâm trầm ngâm về bức tranh trong sơn cốc, nhận ra người trong tranh giống Hoàng Long chân nhân của Hằng Nhạc phái nhưng không thể là một người, càng thấy nơi yêu linh này yêu dị. Âu Dương Hoa giải thích mỗi đêm trăng tròn là đêm yêu linh đi săn mồi, chỉ trong trận pháp mới được bình an, và tiết lộ thiên hạ nơi yêu linh có chín quận; bộ tộc đang ở thuộc Thiên Yêu quận với yêu đế Tai Hư, bát đại yêu soái, thiên vạn yêu binh và hơn trăm thành trì. Lão còn kể quy luật cứ năm trăm năm lại có người bên ngoài tiến vào, gia nhập các quận lấy chiến công thăng tiến và có biến hóa thần kỳ, từng có người ngoài nắm một vị trí bát đại yêu soái. Khi Vương Lâm khoe hơn mười bình ngọc đan dược, Âu Dương Hoa hạ quyết tâm dẫn hắn đi xem vật người bên ngoài cần. Đi qua khu cư dân, Vương Lâm dừng lại xoa đầu một hài đồng v�� nhớ tới Đại Ngưu lúc nhỏ. Tới đáy sơn cốc hình hồ lô, lão chỉ vào khối ngọc yêu linh trắng hình lục giác khảm trong vách đá xanh thẫm — kết tinh tiên lực dùng chữa trị tộc nhân. Vương Lâm chụp lấy tinh thạch, hấp thu khí tức yêu lực cực lạnh chạy theo khớp xương tụ ở đan điền thành tinh thể cỡ hạt gạo, toàn thân biến hóa cực kỳ rõ ràng."},{"chuong":497,"tieuDe":"Hắc Y Nam Tử","tomTat":"Tại thung lũng Hồ Lô Cốc trên Thiên Vận Tinh, Vương Lâm cảm nhận yêu lực kết tinh vừa hấp thu khiến yêu khí trong người biến thành đoàn yêu hỏa, nhận định yêu lực này giống tiên lực nhưng quỷ dị và có thể dung hợp đẩy tu vi. Hắn lấy hơn mười bình ngọc đổi lấy yêu lực kết tinh duy nhất của thung lũng từ Âu Dương Hoa, rồi ngồi thiền suy ngẫm về công dụng ẩn giấu của nó, định thả lỏng tính tình giết chóc như năm xưa ở Tu Ma Hải. Đêm xuống, Âu Dương Hoa cùng dân cốc cầm vũ khí phòng thủ đêm Yêu linh săn mồi và niệm chú duy trì trận pháp đã suy yếu. Vương Lâm tách một tia nguyên thần hóa thần thức phóng đi, thấy yêu linh Đông Hải tạo đạo khí tím khuếch tán hình tròn hủy diệt sinh khí, rồi phát hiện Hắc y nam tử đang hấp thu yêu lực và tuyên bố coi hắn là con mồi. Vương Lâm nhận ra đối thủ là tu sĩ Ứng Biến hậu kỳ đại viên mãn, còn Hắc y nam tử lầm tưởng hắn chỉ Ứng Biến trung kỳ. Khi trận pháp bị sóng yêu khí công phá sắp vỡ, Hắc y nam tử hóa điện quang phi kiếm lao tới, Vương Lâm hiện thân ở cửa cốc bên cạnh Âu Dương Hoa, mở màn cuộc săn."},{"chuong":498,"tieuDe":"Sinh Chi Lạc Ấn","tomTat":"Âu Dương Hoa biến sắc kinh hãi khi nhận ra Vương Lâm; một kiếm quang chém nứt trận pháp thung lũng giam yêu linh, Vương Lâm vỗ túi trữ vật triệu Cấm Phiên gia cố khiến uy lực trận tăng mấy lần rồi bước ra ngoài. Cách mười trượng, hắc y nam tử La mỗ đạp phi kiếm đứng xem giữa sóng yêu linh khí; Vương Lâm diệt một đầu yêu linh thú và lạnh lùng cảnh cáo y rời đi, còn y do dự dò hỏi môn phái vì sợ giết nhầm người quen. Vương Lâm xuất kiếm tiên cùng loan đao làm rạn phi kiếm địch và đả thương ngực La mỗ tuôn huyết quang, buộc y nuốt đan dược khôi phục. La mỗ phản công bằng Địa diệt chi hỏa hóa sáu rồng lửa cùng cấm thuật Kiếm toái; Vương Lâm thi triển Sinh Chi Lạc Ấn — hai ký hiệu hiện mi tâm bao trùm toàn thân — chống đỡ, gây vụ nổ long trời dội ngược cả sóng yêu linh. Vương Lâm bước ra từ bóng tối, xuyên qua khí lãng yêu linh và suýt điểm trúng La mỗ. Cuối chương, La mỗ vạch rõ đối phương chính là đệ tử Thiên Vận Tử, Tử hệ lão thất Vương Lâm dùng cấm pháp Tịch Diệt Chỉ, tu vi Anh Biến trung kỳ nhưng từng đấu mười một trận Vấn Đỉnh, và lo ngại khó hạ sát vì hắn còn pháp bảo bảo mệnh."},{"chuong":499,"tieuDe":"Ma Cấm","tomTat":"Hắc y nam tử — tu sĩ Anh Biến hậu kỳ đại viên mãn tự xưng La mỗ, hành sự thay Tôn sư — phối hợp kiếm vỡ hàn quang và hắc hỏa phá mất một trong ba tầng Sinh chi lạc ấn hộ mệnh của Vương Lâm, khiến hắn tiếc nuối và sát khí đằng đằng. Vương Lâm truy kích bằng roi tiên Côn Cực Tiên; đối phương dùng huyết sắc ngũ sát đan lưới năm sao định phong ấn roi nhưng lần đầu thất bại, bị hắc mang phản khiến tay bốc khói trắng, rồi bị roi quất trúng đả thương nguyên thần. Hắc y nam tử phun độc khí chui vào yêu linh khí lãng rút lui, Vương Lâm niệm thần chú Phong gọi gió phá độc hóa mây thoát ra. Vương Lâm suy đoán đối thủ là người Thiên Vận Tinh vì biết danh tiếng và pháp bảo hộ mệnh của mình, quyết không tha. Hai người rượt đuổi xuyên đêm trong Yêu linh khí lãng, diệt sạch yêu linh cấp thấp và hấp thu yêu khí. Bị loan đao bám sát, Hắc y nam tử hút khói đen vào ngực chịu đau tột độ, thi triển Ma cấm hô “thiên quỷ đệ tứ tôn, hiện!” biến tay trái thành mười Quỷ ảnh quái dị; Quỷ ảnh nuốt luôn kiếm quang của Vương Lâm, còn tơ đen quanh thân hắn cản loan đao không vào gần được."},{"chuong":500,"tieuDe":"Gạt Bỏ","tomTat":"Đối mặt Quỷ ảnh (Thiên Quỷ) của Hắc y nam tử lao tới, Vương Lâm phun ra đại phiên hắc quang cao ba trượng, thả mấy chủ hồn — gồm tàn hồn kỳ lân — làm mồi nhử; Quỷ ảnh nhằm thẳng Anh Biến chủ hồn nên hắn thừa cơ ôm trọn nó, ném Khu Thú Quyển rồi chỉ ngón trỏ về phía đối thủ. Vương Lâm thi triển Hóa ma chỉ — chiêu thứ hai trong Tam thức sát chiêu, chiêu hắn từng dùng đấu Tử hệ lão Tứ — và kích hoạt Sinh chi lạc ấn, ký hiệu xám lan toàn thân giúp hắn xuyên qua khói độc vô hại để đuổi sát. Hai Hóa ma chỉ va chạm tạo tiểu cầu hủy diệt chứa điện quang như Thiên kiếp tiên lôi; Hắc y nam tử khoe mình Anh Biến hậu kỳ đại viên mãn còn Vương Lâm chỉ trung kỳ, nhưng Vương Lâm đáp Thiên Quỷ đã hấp thu tiên lực của hắn. Thiên Quỷ hạ quyết tâm tự sinh hắc quang, xuyên qua yêu linh khí lãng bỏ trốn khiến Hắc y nam tử nổi điên đổ lỗi. Mất quỷ vật hấp thu, hắn dồn gần 90% quỷ tiên lực vào tiểu cầu, đẩy nó áp đảo về phía Vương Lâm. Vương Lâm hô mở Xạ Thần Xa, dùng Cửu Tự Chân Ngôn học từ Ngọc giản tiên nhân khống chế Hồn thú bất khuất nhằm thẳng đối thủ, buộc Hắc y nam tử vỗ mi tâm cho nguyên thần rời cơ thể bỏ chạy; thân xác không hồn ngã ngửa, tiểu cầu đổi hướng lao thẳng về phía nó."},{"chuong":501,"tieuDe":"Sưu Hồn Thuật","tomTat":"Tiểu cầu của hồn thú đáp lên thân Hắc y nam tử, thiêu rụi toàn thân chỉ còn nguyên thần thoát ra; Vương Lâm lần đầu phối hợp ăn ý với hồn thú qua Xạ Thần Xa, thậm chí được nó chủ động cõng bay đi vì chê hắn chậm. Nguyên thần đối phương dùng Tổn Thần thuật bỏ chạy nhưng bị Vương Lâm dùng Côn Cực Tiên quấn bắt, giam vào hồn phiên trước khi kịp tự nổ. Hồn thú phẫn nộ vì bị cướp mồi, Xạ Thần Xa hóa Khu Thú Quyển hút mạnh tiên lực, Vương Lâm phải dùng tiên ngọc chống đỡ. Bị lập cấm chế ngăn tự bạo, Hắc y nam tử lộ thân phận là La Vân người Thiên Quỷ Đạo, dọa sư tôn Quỷ Chân Nhân sẽ báo thù. Vương Lâm thi triển Sưu Hồn Thuật, ép La Vân kêu la khoảng một nén nhang rồi bất động, rút khối kết tinh trong đan điền cùng toàn bộ ký ức. Cuối cùng hắn giam nguyên thần La Vân định luyện thành chủ hồn trong Tôn hồn phiên, hóa tia chớp bay theo hướng chủ hồn đang truy kích Thiên quỷ, ngẫm thấy trong ký ức La Vân có vài thuật ma cấm đáng tu luyện."},{"chuong":502,"tieuDe":"Thủy Cảnh","tomTat":"Vương Lâm nắm trọn ký ức La Vân, qua đó hiểu rõ vùng đất yêu linh chia mười quận, mỗi quận phong ấn một Cổ yêu chi linh — dung hợp được thì tu vi tăng vọt và có cơ hội tiến vào cảnh thần chi thủy, nơi tốc độ cảm ngộ thiên đạo tăng vọt và có thể tự sáng tạo tiên thuật. Hắn xác định kế hoạch của La Vân là nhập một quận để đạt chiến công, quận gần nhất là Thiên Yêu quận cần đủ ba giáp yêu lực; kiểm tra yêu tinh La Vân thấy hai giáp, cộng một giáp đã hấp thu vừa đủ ba giáp, nhờ đó hiểu vì sao La Vân muốn giết mình. Cái tên thần chi thủy gợi Vương Lâm nhớ tới Thủy cảnh cùng tài liệu Cực Cảnh, Đạo cảnh, Thủy cảnh từng chiếm ở động tiên ngầm trong Tu Ma Hải khi còn ở Chu Tước Tinh, và hắn mơ tưởng kết hợp Cực cảnh với Thủy cảnh thành đại đạo luân hồi rồi tự kiềm chế. Hắn dịch chuyển ngàn dặm tới một bình nguyên có khe rãnh, há mồm hút các chủ hồn âm hồn gồm một đầu lân dung nhập vào Tôn Hồn Phiên. Sau đó hắn giải thích cơ chế Thiên quỷ — vật thần thông của Thiên Quỷ Đạo sinh từ hư vô, được luyện thành bản mạng quỷ linh — và việc quỷ linh của La Vân phản chủ do hắn tu luyện quá ngắn. Cuối cùng Vương Lâm dùng thuật đám bụi khí hóa hàn quang truy diệt Thiên quỷ đang suy yếu trốn trong khe, phủ đầy tro bụi lên thân nó."},{"chuong":503,"tieuDe":"Luyện Hồn Tân Tông","tomTat":"Vương Lâm đứng ngoài khe rãnh dụ Thiên quỷ lao ra, dùng Côn Cực Tiên chuyên đánh nguyên thần quất cho nó suy yếu; theo trí nhớ La Vân, hắn biết Thiên quỷ cần bốn chín ngày tu dưỡng sau phản bội nên quyết bắt sống ngay lúc nó yếu nhất. Thiên quỷ giả vờ suy yếu rồi phun Bản mạng chi hỏa hòng hủy roi, nhưng Côn Cực Tiên bất ngờ lóe một đạo kim quang quỷ dị chụp tắt lửa khiến Thiên quỷ suýt tiêu tan; Vương Lâm vội thu roi, dùng hồn phiên cuộn Thiên quỷ vào giữ lại. Sau khi bị lửa đốt, Côn Cực Tiên cuộn lên một lớp da cực cứng như rắn lột da nhưng lột chưa xong. Ba ngày sau hắn về sơn cốc tộc Âu Dương Hoa qua trận pháp dung hợp cấm phiên, vào cấm địa tọa định; Âu Dương Hoa cung kính cung đón thượng tiên, ra lệnh cấm vào sâu thung lũng và tuyên chiến mở rộng địa bàn. Vương Lâm tính ở lại giáo hóa cư dân, truyền thuật hồn phiên để gây dựng lực lượng riêng trước khi tới thành Cổ Yêu, nhắm khôi phục Tôn hồn phiên và đoạt Cổ yêu chi linh. Hắn lưu khẩu quyết Luyện Hồn, Trừu Phách cùng cách chế tác hồn phiên vào hai ngọc giản, cố ý cài một sơ hở trí mạng chỉ mình biết để có thể trực tiếp khống chế hồn phiên của đệ tử."},{"chuong":504,"tieuDe":"Yêu Lực Kết Tinh","tomTat":"Chế tác xong yêu giản, Vương Lâm thả thần thức bao quát thung lũng, thấy cư dân tư chất tốt và nhận định vùng đất yêu linh tuy không có linh lực nhưng có thể dùng yêu lực luyện hồn phiên. Hắn gọi trưởng lão Âu Dương Hoa, trao hai quả ngọc giản chứa khẩu quyết luyện hồn nhưng lão thử mãi không cảm nhận được. Quan sát thấy kinh mạch lão tắc nhiều chỗ, Vương Lâm dùng song chỉ điểm từ bụng lên mi tâm cưỡng ép đả thông, khiến lão đau ngất rồi tỉnh dậy đột phá nhị tinh, tự thấy như được hồi sinh và quỳ tạ thượng tiên. Vương Lâm tuyên bố truyền thụ thuật luyện hồn cho toàn cốc, điều cực hiếm nơi vùng yêu linh, khiến Âu Dương Hoa cảm kích thề khắc cốt và hành lễ như đệ tử. Ba tháng sau, toàn bộ đàn ông trong tộc đạt thành quả, riêng Âu Dương Hoa và một thanh niên thiên phú tiến bộ vượt bậc — thanh niên đã đạt giai đoạn ba, chuẩn bị chế tác hồn phiên. Cùng lúc Vương Lâm dung hợp hai khối yêu tinh thành ‘Ba giáp yêu tinh’ ẩn yêu lực vô biên, nuốt thử thì thân hóa yêu dị nhưng mới đạt Trúc Cơ kỳ vì lượng chưa đủ, rồi rút yêu lực về trở lại trạng thái siêu phàm."},{"chuong":505,"tieuDe":"Thập Tam","tomTat":"Tại sơn cốc ở Thiên Vận Tinh, Vương Lâm chế hồn phiên thay thế từ cươn thụ chi mộc, da dã thú và thủ ấn để bù tài liệu thiếu khuyết — thứ này chỉ phong ấn được không quá mười hồn phách và ẩn một sơ hở trí mạng chỉ hắn biết. Hắn khắc phương pháp lên ngọc giản rồi trao cho Thập Tam, thanh niên có ngộ tính trời sinh với Luyện Hồn Thuật mà hắn âm thầm theo dõi, khiến Thập Tam run rẩy quỳ lạy ba lạy. Âu Dương Hoa trình kế hoạch một tháng sau tấn công một bộ tộc vài chục người cách ngàn dặm, Vương Lâm chỉ đáp “Tùy ngươi!”. Sau ba lần thất bại, Thập Tam chế thành cây hồn phiên bảy thước đầu tiên và triệu hồn phách sư tử cánh dài; Âu Dương Hoa tuy chế xong trước đã cố ý nhường cơ hội cho hắn. Khi Thập Tam hô “Thu!”, sư tử quay đầu phản phệ lao vào hắn đầy sát khí, Âu Dương Hoa triệu chim sẻ chặn nhưng không kịp, Thập Tam bị giam cầm suýt chết. Vương Lâm một tiếng hừ “Nghiệt súc, ngươi dám!” khiến sư tử tan nát rồi thuần phục, lướt mấy trăm trượng hiện thân, để lộ rằng hắn đã cải biến Luyện Hồn Thuật cài backdoor khống chế mọi hồn thú do người học phong ấn."},{"chuong":506,"tieuDe":"Tán Hồn Dưỡng Phách","tomTat":"Vương Lâm khống chế con sư tử yêu thú hóa thành hắc mang nhập Hồn Phiên làm chủ hồn cho Thập Tam, đồng thời cảnh cáo Luyện Hồn Thuật không thể nhờ thủ thuật vì chủ hồn có thể cắn trả. Một tháng sau, Âu Dương Hoa và Thập Tam dẫn mười nam nhân đánh hạ bộ tộc trong động dưới lòng đất; Vương Lâm coi đây là thử thách và không can dự, nếu họ bại sẽ rời đi tới Cổ Yêu thành. Đội thắng trận trở về, trưởng lão đối phương bị nuốt và luyện hóa thành chủ hồn thứ hai của Thập Tam. Người ngoại tộc bị bắt uống yêu thang để xóa ký ức rồi nhồi danh tính mới, dần thành tộc nhân. Âu Dương Hoa dâng nhị giáp yêu tinh, Vương Lâm nuốt dung hợp thành ngũ giáp và ban khẩu quyết Luyện Hồn Thuật giai đoạn bốn, lập ra ba cách lập công để đổi khẩu quyết. Vương Lâm tính kế ‘tán hồn dưỡng phách’: để tộc nhân phong ấn hồn phách vào Hồn Phiên, đợi th��i cơ chín muồi khởi ý thu về nhằm hồi phục thập ức tôn Hồn Phiên. Bộ lạc bùng nổ tu hành, chuyển sang xâm lược, chia ba nhóm đồng thời đánh ba bộ lạc khác, một lực lượng âm thầm trưởng thành giữa cảnh chém giết kéo dài cả trăm năm."},{"chuong":507,"tieuDe":"Chiến Thư","tomTat":"Trong ba tổ đi đánh bộ lạc, hai tổ thắng trở về còn tổ Thập Tam mất tích; ba ngày sau chủ hồn sư tử có cánh mang Thập Tam toàn thân loang máu, ngực có yêu vật tơ hồng ký sinh, bay về thung lũng. Vương Lâm thu chủ hồn sư tử thành dấu ấn ngón tay, rút sợi tơ hồng đốt thành tro, cứu Thập Tam khỏi cơn nguy hiểm nhưng xác nhận hắn đã bị phế: kinh mạch nát, mất sạch yêu lực tam tinh, hồn phiên bị cướp. Qua lời Thập Tam, Vương Lâm hiểu lão già áo trắng (chấp sự dưới trướng Tả Dực tướng quân ở Cổ Yêu thành) đã cố ý dùng Thập Tam làm chiến thư sống để dụ hắn lộ diện và moi khẩu quyết cờ kỳ quái. Vương Lâm tới đồng bằng Thiên Thủy, không phá nổi trận pháp viễn cổ mười dặm nên dùng Khai Thiên phủ đào vòng quanh ven trận rồi nhổ cả mảnh đất mười dặm bay lên, mang về thung lũng để Hồn phiên (sáu chủ hồn phun lửa tím) luyện hóa bảy ngày bảy đêm. Hắn cân nhắc truyền thuật Cổ Thần cho Thập Tam nhưng từ bỏ vì rủi ro chết và không chắc Cổ Thần cắn nuốt được yêu lực; Thập Tam tỉnh dậy, dập đầu ba cái r��i đi, về phòng cố thổ nạp đến phun máu hôn mê. Lão áo trắng tự ra ngoài trận hạ chiến thư đòi đánh tay đôi, bị Vương Lâm bóp cổ giết “rắc”, nguyên thần giam vào cờ Tôn Hồn, xác bị đốt thành tro; lão áo xám sợ hãi mở trận pháp quy thuận. Vương Lâm thu nạp toàn bộ dân Thiên Thủy, dung hợp ba trận thành trận bảo vệ hai mươi dặm, Âu Dương Hoa đặt tên bộ lạc là Luyện Hồn với hơn năm trăm nam đinh; thung lũng cũ thành vùng cấm chỉ Vương Lâm ở. Hai năm hấp thu yêu lực từ vạn vật (cả bông tuyết), Vương Lâm nâng yêu tinh từ năm giáp lên ba mươi bốn giáp, tiên ngọc gần đủ Anh Biến hậu kỳ, mở ra con đường dùng yêu lực thay tiên ngọc; bộ lạc Luyện Hồn mỗi tháng đánh chiếm bộ lạc nhỏ thu tù binh và yêu tinh."},{"chuong":508,"tieuDe":"Chương 508","tomTat":"Vương Lâm mất ba ngày mở rộng trận pháp bộ lạc Luyện Hồn lên bốn mươi dặm, rồi dùng Tôn Hồn phiên hóa màn sương đen bao trùm tế dưỡng hồn phách cho toàn tộc, biến nơi đây thành dấu hiệu độc đáo. Âu Dương Hoa mang thợ săn Thập Tam bị dã thú yêu hóa làm trọng thương tới cầu cứu; Vương Lâm dò ra Thập Tam đã tự phát luyện thể nhờ tích yêu lực trong xương cốt máu thịt, gần đạt nhị tinh nhưng sẽ chết nếu tiếp tục mù quáng. Dùng Nguyên thần đọc trí nhớ và cảm động trước sự kiên trì hơn một năm của hắn, Vương Lâm cứu chữa và truyền Luyện Thể thuật của Cự Ma Tộc qua ngọc giản, hứa truyền khẩu quyết tầng một Cổ Thần nếu thành tựu. Qua bốn năm bộ lạc bành trướng tới gần ba trăm dặm với hơn năm nghìn nam đinh, thôn tính hầu hết mười vạn dặm; Thập Tam thành tựu thân cứng như sắt còn Hổ Bào trỗi dậy tới giai đoạn thứ năm ngang Kết Đan kỳ, được xem là thiên tài. Cuối cùng Vương Lâm luyện hai ngọc giản truyền âm làm đường lui, dẫn Thập Tam và Hổ Bào rời bộ lạc nhắm tới Cổ Yêu thành. Cách bộ lạc mười dặm, hắn triệu Văn Thú — con thú vàng tím mang Kim linh căn thực lực ngang Hóa Thần hậu kỳ đại viên mãn — làm tọa kỵ lên đường."},{"chuong":509,"tieuDe":"Chương 509","tomTat":"Vương Lâm thu phục yêu thú Văn Thú tỏa khí âm hàn, cưỡi nó chở Thập Tam và Hổ Bào vượt ba ngàn vạn dặm, bảy ngày tới Cổ Yêu thành trong Thiên Yêu quận, trên đường nảy ý dung hợp các bộ lạc Yêu linh chi địa cho bộ lạc Luyện Hồn của mình. Tại cửa Bắc, hắn không thu liễm tiên lực mà phá quy củ đi thẳng vào; Thập Tam dùng thuật Luyện thể Cự Ma Tộc đấm vỡ trường thương thị vệ và bị Vương Lâm quở vì chưa khống chế lực tùy tâm. Khi hơn mười yêu binh vây công, Vương Lâm tùy ý đánh một quyền vào không trung khiến cả đám đông cứng rồi bị đẩy bay thổ huyết, hút máu tạo quả cầu máu bắn vào tường thành. Diêu Nghiêu lĩnh — nữ tử áo trắng quen biết cũ — lao ra hóa giải cầu máu, từ chối giao chiến và dẫn hắn qua Truyền tống trận tới gặp Tả dực Yêu tương. Tả dực Yêu tương yêu lực gần Vấn Đỉnh đánh thử một quyền, Vương Lâm hóa giải bằng Tịch Diệt chỉ rồi từ chối chức Trưởng lão vì chỉ muốn chức ngoài có binh quyền. Yêu tương bèn ra Thập Băng Chiến Ý gồm mười quyền biến hóa chồng chất, hứa tiếp được sẽ ban chức Đô thống. Vương Lâm đứng vững như cây tùng, vận Sát lục tiên quyết kết hợp Hóa Ma chỉ nghịch hóa tiên lực thành ma khí mà đón đòn."},{"chuong":510,"tieuDe":"Chương 510","tomTat":"Chương mở đầu bằng lai lịch ba sát chiêu Tư Đồ Nam sáng tạo và truyền cho Vương Lâm — Tịch Diệt chỉ, Hóa Ma chỉ và Hoàng Tuyền chỉ; trong đó Hoàng Tuyền chỉ mạnh nhất, uy lực gần Tiên thuật cấp thấp nhưng dùng nhiều sẽ kéo đạo tâm nhập ma, Vương Lâm chỉ từng dùng một lần khi đánh Trần Đào. Tại Cổ Yêu thành, Vương Lâm giao chiến với Tả dực Yêu tương dưới thần công Thập Băng Quyền Ý gồm tám lần sụp đổ vô hình, càng về sau càng mạnh. Hắn lần lượt dùng Hóa Ma chỉ chống lần thứ nhất, Sát lục tiên quyết tạo rồng khí xám và lốc xoáy giết chóc cho lần thứ hai, rồi ngưng thành trường kiếm bảy thước khí xám chém vỡ lần thứ ba. Tả dực Yêu tương khen hắn là số ít người phản công được và thách phá đủ tám lần sụp đổ; Diêu Tích Tuyết đứng xa hồi tưởng ba năm trước nàng bại ở lần thứ tám và nhận chức Thống lĩnh. Đến lần sụp đổ thứ tư mạnh gấp ngàn lần khiến trường kiếm vỡ nát, Vương Lâm không muốn lộ Hoàng Tuyền chỉ ở Yêu linh nên thu khí xám lại, hiện hai đạo Sanh ấn phòng hộ trên mi tâm. Giữa đợt công kích, hắn cảm ngộ một niềm tin vô bờ bến ẩn trong quyền ý, ánh mắt sáng ngời như Chu Dật năm xưa lúc linh lực thiêu đốt ngộ ra."},{"chuong":511,"tieuDe":"Rời Đi","tomTat":"Khi chống chịu lần sụp đổ thứ tư của Thập Băng Quyền Ý, Vương Lâm cảm nhận được ‘niềm tin tất thắng’ mà Tả dực Yêu tướng tích lũy từ tâm niệm vô số kẻ bại trận, ngộ ra bản chất quyền ý chính là Thần thông Niềm tin và mấu chốt phá nó không nằm ở tu vi mà ở niềm tin. Bị đánh văng nghìn trượng, Sanh ấn ở mi tâm chỉ còn nửa đạo, hắn dung niềm tin vào Hóa Ma chỉ và lần đầu thi triển uy lực chân chính: tiên lực vô thanh hóa thành ma khí, tóc dài quá gối, ma văn xanh bạc hiện ở mi tâm, Sanh ấn phục hồi đầy đủ bao trùm toàn thân. Nhờ đó hắn phá liên tiếp lần sụp đổ thứ năm và thứ sáu, rồi chỉ bằng hai chữ ‘Nhường đường’ chứa niềm tin vô bờ mà phá tan lần thứ bảy. Hắn lĩnh ngộ thêm ‘Ma niệm’ — nghịch thiên tùy ý, phá hư đạo pháp, tự đi con đường riêng. Tả dực Yêu tướng rốt cục biến sắc, thừa nhận đã xem thường đối phương và lần đầu xúc động sau mấy ngàn năm, gọi Vương Lâm là người đầu tiên cảm ngộ được dưới quyền ý này. Diêu Tích Tuyết đứng quan sát ở xa cũng kinh ngạc, nhớ lại lời phụ thân Huyết Tổ rằng người có chú ý đến Vương Lâm."},{"chuong":512,"tieuDe":"Khảo Nghiệm Của Yêu Tương","tomTat":"Ở trạng thái nhập ma với ma khí xông trời, Vương Lâm vượt qua bảy lần ‘sụp đổ’ của Thập Băng Quyền do Tả Dực Yêu tương thi triển, đối kháng được lần thứ tám hóa dạng nước lũ; khi lần thứ chín im lìm áp tới, hắn quyết đoán lùi ra nghìn trượng để bảo toàn đạo tâm thay vì liều đánh. Tả Dực Yêu tương khen hắn biết tiến biết lùi, xưng danh đầy đủ là Vân Lệ Hải, phong Vương Lâm làm Thống lĩnh Cổ Yêu thành nắm một vạn yêu binh và trao một lệnh bài đồng; Diêu Tích Tuyết định nói gì đó nhưng bị hắn phớt lờ. Vào trung tâm thành, Vương Lâm khoanh chân thổ nạp bốn ngày để khôi phục đạo tâm, nén ma niệm thành một điểm phong ấn giữ làm uy lực thay vì loại bỏ, đồng thời làm rõ động cơ nhập ma là lĩnh ngộ Niềm tin và đoạt chức vị bên ngoài. Thập Tam và Hổ Bào hội hợp, cùng hắn dạo Cổ Yêu thành; Vương Lâm ngờ cả vùng Yêu linh Đông Hải là động phủ một vị tiên đế, cư dân như gia súc trong ‘hàng rào tre’. Tại quán Trúc Thanh lâu có vò rượu khổng lồ, hắn uống rượu Trúc Thanh và hoài niệm loại rượu duy nhất từng uống thời phàm nhân ở Chu Tước Tinh do Đại Ngưu để lại, băn khoăn không biết Đại Ngưu và con cháu nay còn bình an."},{"chuong":513,"tieuDe":"Ngộ Trong Chiến Đấu","tomTat":"Vương Lâm uống rượu cùng Thập Tam và Hổ Bào, chìm trong hồi ức hơn mười năm sống đời phàm nhân và nhớ Đại Ngưu cùng Chu Tước tinh, sinh niềm xúc động mãnh liệt muốn rời Yêu Linh chi địa và Thiên Vận tinh để trở về cố hương. Sự xúc động kéo dài bất thường khiến tâm ma bị áp chế lớn mạnh, chén rượu vỡ cắm vào tay mà hắn không hay. Bảy tám yêu binh hắc giáp do một thống lĩnh nét mặt âm trầm dẫn đầu xông vào tửu lâu gây sự; hắn vốn là Nghiêu Lĩnh chính bị một người ngoài đến chiếm chỗ nên bất mãn, ném hai vò rượu dò xét rồi tấn công bàn Vương Lâm, định dùng Tru Tiên trận. Thập Tam giơ tay bắt vò rượu thứ hai bị thương, sau đó tung một quyền đánh trọng thương một yêu binh dù Luyện Thể thuật chưa đầy đủ. Hổ Bào lấy mười lá cờ nhỏ rồi phất Hồn phiên thả vô số hồn phách, nhưng sáu yêu binh dùng Yêu lực phá thần bức lui, hai thuộc hạ quyết tử bảo vệ lão tổ. Thống lĩnh chợt biến sắc hô thu hồi yêu lực nhưng đã muộn, sáu đạo yêu lực mất khống chế bay thẳng vào mi tâm Vương Lâm. Ma niệm hút trọn khiến hắn bừng tỉnh khỏi hồi ức, ánh mắt trở lại trong sáng, thở dài thốt rằng ma niệm lợi hại thật, trong mắt hiện chút kinh hãi."},{"chuong":514,"tieuDe":"Ma Niệm","tomTat":"Sau cơn đắm chìm vào hồi ức tại tửu lâu, Vương Lâm nhận ra tình cảnh vừa rồi chẳng khác kiếp nạn vì trong người vẫn còn chút ma niệm di chứng từ lần nhập ma trước, chính nó lôi ký ức Chu Tước tinh ra khiến tinh thần mất kiểm soát; chương cũng luận giải hai quan điểm về thiên ma ngoại vực giữa tu sĩ thượng cổ và tu chân liên minh. Nhân lúc yêu lực sáu yêu binh tung hoành, hắn tìm được đường đột phá trong nghịch cảnh, dung hợp yêu lực vào tiên lực rồi cắn nuốt toàn bộ sáu luồng yêu lực, thần trí lập tức khôi phục. Khi rời tửu lâu, một nam tử âm trầm tán phát yêu lực ngưng thành trường kiếm tấn công nhưng bị Vương Lâm vung tay tạo gió hóa giải, để lại lời sẽ còn gặp lại. Về khách sạn, hắn vận tiên lực dò khắp cơ thể suốt hai ngày, khu trừ sạch ma niệm kết thành ba quả cầu đen và thu vào túi trữ vật làm thủ đoạn về sau. Hết hạn bảy ngày, quản sự tham quân dưới trướng Yêu Tương tới kiểm tra lệnh bài đồng rồi vẽ Truyền Tống trận bằng máu do Yêu đế tạo để đưa đi. Tới quân doanh, ba người chịu sóng âm chấn động khiến Thập Tam phun máu và Hổ Bào loạn yêu lực, đều được Vương Lâm truyền lực cứu chữa; cuối cùng hắn đứng giữa hơn vạn yêu binh giáp đen đầy sát khí mà vẫn hết sức bình thản, ��áp lại bằng ánh mắt lạnh lẽo."},{"chuong":515,"tieuDe":"Thống Lĩnh","tomTat":"Vương Lâm vừa từ pháp trận bước ra, một vạn yêu binh Hắc Giáp quân mặc giáp đen đồng loạt hét vang đầy sát khí; Quản sự tham quân giới thiệu hắn là tân thống lĩnh và Tư Mã Viêm là phó thống lĩnh. Tư Mã Viêm cưỡi cự thú một sừng tới, tháo mũ để lộ khuôn mặt âm trầm chính là người từng gặp ở tửu lâu, xưng ra mắt thống lĩnh, còn Vương Lâm chỉ bình thản đáp lại. Quản sự tham quân cáo từ về phục mệnh Yêu Tương đại nhân rồi vào trận pháp biến mất. Khi Vương Lâm lệnh toàn quân lui ra, không một yêu binh nào động đậy cho tới khi Tư Mã Viêm lên tiếng, chúng cười khinh miệt sau lưng ba người. Không có chỗ ở, Vương Lâm cùng Thập Tam và Hổ Bào ngồi thổ nạp ngoài bãi đất trống suốt ba ngày, dùng thần thức quan sát toàn quân và nắm rõ cơ cấu mười Thống đội. Dựa vào ghi chép tổ tiên do La Vân đưa, hắn hiểu rõ quy tắc Cửu quận yêu binh cùng quy định mười người không nghe hiệu lệnh nên ẩn nhẫn chờ thời cơ chỉnh đốn như thợ săn rình mồi. Tư Mã Viêm ngày càng khiếp sợ vì không nhìn thấu vị tân thống lĩnh, bèn triệu tập các thống đội bàn về Vương Lâm và được báo hai người Từ U, Chu Khải vắng mặt."},{"chuong":516,"tieuDe":"Yêu Binh","tomTat":"Trong quân doanh Thiên Yêu quận, các thống đội của Tư Mã Viêm bàn về thống lĩnh mới Vương Lâm; một lão già giáp đen cho rằng kẻ ngồi im nửa tháng không mất bình tĩnh ắt tâm cơ thâm trầm, còn Tư Mã Viêm chốt sách chờ Vương Lâm chủ động ra tay rồi mới đối phó. Vương Lâm ẩn nhẫn thổ nạp nửa tháng, mặc kệ hơn vạn yêu binh khinh miệt, cho tới khi Tôn thống đội nhổ nước bọt gọi hắn là phế vật. Vương Lâm giơ tay trói kéo Tôn thống đội lại, sai Thập Tam đọc điều thứ tám quân quy rồi bóp nát cổ, phá tu vi và hút yêu khí từ thất khiếu xác chết. Khi nửa ngàn yêu binh lao tới báo thù, hắn lấy kiếm tiên và loan đao chém giết dễ dàng, rồi duỗi tay hấp thu yêu lực mấy trăm xác chết tạo thành lốc yêu lực quanh thân. Chín thống đội cùng chín ngàn yêu binh kéo tới vây trận, Hổ Báo xuất hồn phiên còn Thập Tam đứng cạnh, nhưng Vương Lâm vẫn ngồi khoanh chân. Tư Mã Viêm phóng tới chất vấn việc giết Tôn thống đội và trảm yêu binh, liền bị Vương Lâm sai Thập Tam viện dẫn điều mười ba và điều hai quân quy ép cả đám phải lùi và giải tán trong số nhịp hô hấp quy định. Tư Mã Viêm hiểu ra Vương Lâm ngồi im cả tháng chính là để chờ cơ hội này, ba thống đội né tránh tranh giành, còn Thập Tam bắt đầu đếm ngược nhịp hô hấp."},{"chuong":517,"tieuDe":"Doanh Trại Hắc Giáp Quân","tomTat":"Tư Mã Viêm hạ lệnh chín ngàn yêu binh tản ra phá thế bao vây, thì quản sự tham quân gầy gò cùng một lão già áo vải bố tóc bạc theo luồng sáng đỏ như máu hiện thân thị uy; chỉ một cái liếc mắt của Vương Lâm khiến một trong bốn phong ấn trong thân lão già suýt vỡ. Vương Lâm ném ngọc giản lưu hình ảnh chứng minh thống lĩnh giết người vô cớ, quản sự xem xong bỏ ý truy cứu, sinh lòng kết giao và hứa bẩm báo Yêu Tương đại nhân, khiến Tư Mã Viêm cùng đám thống đội buộc phải nhận lỗi thỏa hiệp. Vương Lâm nhấn tay dựng lên một ngôi lầu hai tầng bằng bùn đất, chấn nhiếp toàn doanh và lập uy danh; sau mấy tháng thổ nạp luyện hóa yêu lực dung nhập tiên lực, hắn tiến tới Anh Biến hậu kỳ, còn Hổ Bào hòa nhập quân doanh và rung động với nữ thống đội Từ U. Ở quân doanh thứ ba, đêm trăng tím nửa-năm-một-lần, Diêu Tích Tuyết dùng la bàn đỏ, cây đèn trắng và giọt máu lam thi triển pháp thuật xông vào vực sâu nơi thủy triều theo kế hoạch của phụ thân. Lần thứ tư nàng vẫn thất bại, nhờ Huyết Hồn đan mới tái sinh trở về, đã phá được hơn một nửa; nàng nghĩ nếu có người giúp nhất định thành công và gọi tên Vương Lâm."},{"chuong":518,"tieuDe":"Sự Im Lặng Đáng Sợ","tomTat":"Trong Cổ Yêu thành, Diêu Tích Tuyết tính toán nhân lực và kết luận chỉ Vương Lâm đủ tu vi tiếp được Thất Băng quyền của Yêu Tương để nhờ cậy, bèn truyền âm hẹn hắn lúc canh ba ở cổ sơn cách quân doanh ngàn dặm. Vương Lâm khi đó đang khổ tu trong Hắc Giáp quân, sau khi hấp thu yêu lực năm trăm yêu binh và Tôn thống đội thì yêu tinh trong người đạt gần ngàn giáp, nên hắn phớt lờ lời hẹn để dồn sức đột phá Anh Biến hậu kỳ. Đợi tới bình minh không thấy hắn, Diêu Tích Tuyết nổi giận hóa tia sáng trắng xông thẳng vào quân doanh, khống chế Thập Tam bằng tia sáng đỏ và phong tỏa chín ngàn yêu binh. Vương Lâm dùng một cơn gió giải trừ khống chế trên Thập Tam rồi tiếp chuyện nàng trong lầu tối, cảnh cáo nếu không có việc khiến hắn động tâm thì chớ trách. Diêu Tích Tuyết cầu hắn cùng phá một trận pháp cấm chế mười tám phong ấn mà nàng chỉ phá được tới cái thứ mười một, hứa cung cấp toàn bộ tiên ngọc đủ để hắn đạt Vấn Đỉnh sơ kỳ. Nội tâm nàng giấu việc phá trận mang tính sinh tử — đã thất bại bốn lần, chết bốn lần và hao bốn viên Huyết Hồn đan trong mười ba viên phụ thân luyện. Vương Lâm dao động mạnh trước mồi tiên ngọc nhưng nghi nàng che giấu nhiều chuyện, không đồng ý ngay mà hẹn sau bốn tháng sẽ cho câu trả lời thuyết phục."},{"chuong":519,"tieuDe":"Lập Uy","tomTat":"Diêu Tích Tuyết trình bày yêu cầu nhờ Vương Lâm giúp bài trừ phong ấn cấm chế bí mật trên người nàng, thứ phải đợi tới Vấn Đỉnh kỳ mới tự giải được. Tin chắc thực lực hắn sau trận đánh với Yêu Tương, nàng đưa thù lao hậu hĩnh nhưng Vương Lâm liên tục trì hoãn để nâng giá khiến nàng nổi giận. Cuối cùng nàng giao cây đèn Huyết Hồn đan — đồn rằng giúp sống lại một lần dù nguyên thần bị diệt — ném thêm túi tiên ngọc đủ tu tới Anh Biến hậu kỳ cùng lời hứa lệnh bài Huyết Phù, hẹn ba ngày sau canh ba lên cổ sơn. Sinh nghi vì sự hào phóng khác thường, Vương Lâm triệu hồn phách Tào Nhất Đấu ra giám định. Tào Nhất Đấu xác nhận đèn đúng là Huyết Hồn đan với 3614 ký tự phù văn, một trong ba bảo vật Thiên Vận tinh của Huyết Tổ. Tuy nhiên cả hai đoán ra đây thực chất là phế đan chứa độc tố, do Huyết Tổ cố ý tung ra lẫn lộn để bảo vệ bảo vật thật khỏi bị cướp đoạt."},{"chuong":520,"tieuDe":"Diêu Tích Tuyết","tomTat":"Từ việc Tào Nhất Đấu thân phận thấp không biết phân biệt Huyết Hồn đan, cộng thái độ hào hiệp của Diêu Tích Tuyết, Vương Lâm suy ra mọi việc là mưu kế của Huyết Tổ và xác định viên Huyết Hồn đan nàng đưa là đan giả khiến người dùng tử vong; hắn không vạch trần mà lặng lẽ cất cây đèn vào túi trữ vật. Thu túi trữ vật chứa đủ tiên ngọc để tu tới Anh Biến hậu kỳ, hắn chìm xuống lòng đất ba ngày, dựa kết cấu yêu tinh học ở bộ lạc Luyện Hồn cô đọng tiên lực thành ‘Tiên tinh’. Đúng hẹn dưới trăng tím trên cổ sơn ngoài quân doanh ngàn dặm, Diêu Tích Tuyết xuất bảy pho tượng đỏ, cắn lưỡi vẽ ký tự máu dựng trận ẩn thân khiến thần thức không soi thấy chính mình, nói cả Yêu Tương cũng không phát hiện. Nàng dùng la bàn đỏ canh yêu khí cực điểm, dẫn hắn vượt truyền tống trận do Huyết Tổ bố trí, hứa trao lệnh bài Huyết Phủ và tiên ngọc khi trở về. Hai người tới một không gian như tinh không chỉ toàn ánh sáng, có bình đài trăm trượng đặt trận pháp cùng quỹ tích với trận bảy pho tượng. Vương Lâm nhận ra con đường uốn lượn trước mặt là thân giao long Tôn Long do thần thông bố trí, không có trong ký ức Cổ Thần Đồ Ti; vừa khoanh chân chuẩn bị cảm ngộ ý cảnh tạo ấn ký thì trong đầu chợt nảy một ý nghĩ."},{"chuong":521,"tieuDe":"Giao Dịch","tomTat":"Trong Yêu Linh chi địa, Vương Lâm phỏng đoán nơi này do một vị Tiên đế bố trí, ngồi tĩnh tâm cảm ngộ ý cảnh Sinh Tử luân hồi (tay trái sinh, tay phải tử, giữa là thời gian bất biến) mà vẫn phân một niệm cảnh giác Diêu Tích Tuyết. Một lực lượng thần bí từ trời giáng xuống ngưng tụ vào mi tâm Diêu Tích Tuyết, để lại kim phù ấn ba nét tỏa uy nghiêm như vô thượng tiên tôn. Khi lực lượng ấy vờn quanh Vương Lâm, hắn dùng ấn ký Sát Lục chi đạo cùng Sinh ấn, chọn nghe thanh âm thay vì nhìn ảnh, nắm bắt được tiếng tự xưng “Ta là Thanh Sương” và đắc kim phù ấn sáu nét phức tạp hơn. Kim phù sáu nét của hắn lấn át kim phù ba nét của Diêu Tích Tuyết khiến nàng khó chịu, vô thức tránh ánh mắt rồi dẫn hắn lên con đường Tôn Long lắc lư trong hư không. Đi cực nhanh ba ngày mới được một phần ba đường, hai người tới bình đài phong ấn đầu tiên với pho tượng đá cao ba trượng. Diêu Tích Tuyết kích hoạt tượng (uy lực ngang Anh Biến sơ kỳ) rồi ném ngọc phù màu máu hô “Phong!” phong ấn dễ dàng, hẹn Vương Lâm phá giải tầng thứ hai, khiến hắn hiểu thêm về thực lực của nàng."},{"chuong":522,"tieuDe":"Huyết Hồn Đan","tomTat":"Vương Lâm thầm đoán cái ngọc phù đỏ như máu của Diêu Tích Tuyết do phụ thân nàng — Huyết Tổ — luyện chế, rồi dùng Sinh ấn ngưng vào hai mắt nhìn xuyên áo đỏ, phát hiện trong tượng đá ẩn một ký hiệu chỉ có một nét. Hắn suy ra ký tự một nét là thứ cơ bản chung của ký tự ba nét (Diêu Tích Tuyết) và sáu nét (chính hắn), đồng thời nhận định nàng có Huyết Hồn đan nên dù bị đánh lén cũng sống lại, rất khó giết. Sau bảy ngày hai người tới bình đài thứ ba có tượng đá thêm con mắt thứ ba; Diêu Tích Tuyết nhường hắn thử trước. Tượng thức tỉnh đuổi giết, Vương Lâm chống đỡ bằng Sinh ấn và Cấm phiên (đã tích 999 đạo cấm chế), dần nhìn thấu tượng vốn chỉ là một đống cấm chế chồng lớp. Hắn hấp thu rừng cột đá nhọn vào Cấm phiên, phun máu triệt tiêu ánh sáng vàng từ con mắt thứ ba và hét phá vỡ tượng. Cuối cùng hắn vẽ ký tự hai nét bằng tiên lực, hút lấy ký tự vàng dung hợp vào nét vẽ của mình."},{"chuong":523,"tieuDe":"Tiên Tinh","tomTat":"Trên đài phong ấn đường Tôn Long, Vương Lâm vẽ thành công ba nét phù văn, kim quang phát ra ẩn chứa ấn ký thiên đạo và buộc Diêu Tích Tuyết phải dùng huyết ngọc trăm năm hóa giải. Hai người vượt các tầng phong ấn tới đài thứ mười hai — một cửa đá hình mặt người — nơi Động Phủ Chi Linh hiện ra, đòi qua được ba đạo kiếm khí mới được vào động phủ tiên nhân, bằng không cả hai phải chết. Vương Lâm tự xưng chỉ Anh Biến trung kỳ, cố ý trúng đạo kiếm khí thứ nhất rồi chấn nát tiên tinh giấu trong người để bùng tiên lực, diễn cảnh trọng thương văng vào hư vô đánh lừa Diêu Tích Tuyết. Nàng gắng tiếp hai đạo kiếm khí còn lại đến cạn tiên lực, ngồi xuống vận công đối kháng. Đúng lúc nàng lơ là, Vương Lâm đội mũ rơm Vân Tước Tử che thần thức bay lên, điểm mi tâm phong ấn nàng giữa sự sống và cái chết, làm đứt kinh mạch và vô hiệu Huyết Hồn Đan. Hắn vạch rõ toàn bộ mưu kế, đoạt bốn túi trữ vật giấu trên người nàng, liên hệ cảnh hài cốt thiếu nữ bị phong ấn từng thấy trên Chu Tước Tinh năm xưa. Cuối chương, hắn không giết mà giam Diêu Tích Tuyết trong trạng thái không thể chết rồi đề nghị một cuộc giao dịch."},{"chuong":524,"tieuDe":"Sáu Nét Kim Phù","tomTat":"Vương Lâm đề nghị giảm năm mươi năm trong năm trăm năm phong ấn để đổi một câu trả lời từ Diêu Tích Tuyết, cảnh báo nếu nàng nói dối thì sau này y sẽ không tới mở phong ấn; nàng chỉ đáp muốn vào động phủ không có nguyên nhân nên bị y bủa cấm chế nhốt vào quả cầu hắc quang cất vào túi trữ vật. Vấn đáp với Động Phủ Chi Linh hiện hình người đàn ông trung niên dưới cửa đá, y biết được hai người đủ tư cách vào vì cùng tiếp ba đạo kiếm khí, rằng ký hiệu vàng trên mười một đài là Hộ Phủ Thần Thông, mở một phong ấn sẽ thu quyền hạn nhưng động phủ tự đóng, người vào trước đều đã chết, muốn rời đi phải mở một đạo thảo ấn. Vào trong, y phát hiện toàn động phủ dựng bằng Tiên Ngọc phủ tiên cấm tiên giới nên không thể đào, lò luyện đan đã bị vét sạch, và đọc ra dấu vết ba tiền nhân: một người dùng Mai Hoa Thập Bát Cấm vào đầu chỉ lấy vật quý, hai kẻ sau cưỡng ép phá lấy đồ. Theo hành lang tiên ngọc rẽ phải qua rừng trúc, y tìm thấy một khu vườn còn nguyên vẹn cấm chế là trung tâm của mọi cấm chế nên tiền nhân mạnh nhất cũng phải rút lui. Vương Lâm thôi diễn hai tháng, liên tục dẫn phát thử từ ba nghìn lên hơn vạn biến hóa, khi chín trăm chín mươi chín tổ cấm chế trên cấm phiên hoàn thành thì phá vỡ bình cảnh, độ nắm chắc tăng từ bốn lên năm phần. Y men theo đường sinh tiến vào, tới cách bàn đá ba bốn trượng thì trận pháp đột nhiên xoay ngược đổi phương hướng vận chuyển, nổ cơn lốc đen sấm chớp như Du Long đặt y vào thế hiểm nghèo."},{"chuong":525,"tieuDe":"Ba Ký Tự Hợp Làm Một","tomTat":"Sau mười lần hít thở, cơn lốc và tia chớp đen tan biến, Vương Lâm tiến vào bàn đá và kích hoạt chùm sáng cao vạn trượng mở ra động phủ với giả sơn, cỏ xanh, rừng trúc nối liền bốn phía. Một âm thanh từ hư vô trao cho hắn tư cách sở hữu động phủ cùng Động Phủ Lệnh bằng thủy tinh phát sáng bảy màu. Hắn phá cấm chế trên bầu rượu bằng kỹ thuật con sóng và vòng nước xoáy, đoạt được bầu rượu chứa khoảng mười giọt mỹ tửu. Uống một giọt, toàn thân đỏ bừng, tiên lực điên cuồng lưu chuyển và cơn say đẩy hắn vào giấc ngủ say suốt một năm. Trong giấc ngủ tiên lực tăng trưởng kinh người, Yêu Tinh trong đan điền vỡ tan hòa vào tiên lực; tỉnh dậy hắn kinh hoàng nhận ra tu vi đã vượt xa Anh Biến hậu kỳ đại viên mãn, chỉ chờ ý cảnh là đủ sức trùng kích Vấn Đỉnh. Hắn phong ấn cất kỹ bầu rượu, lo lắng không biết đã ngủ bao lâu, rồi dùng lệnh bài rời khỏi động phủ và dự định quay lại khai thác kho bí mật cùng căn từ đường chưa khám phá trong rừng trúc."},{"chuong":526,"tieuDe":"Xoay Chuyển Càn Khôn","tomTat":"Sau khi đột phá Anh Biến hậu kỳ đại viên mãn trong động phủ Huyết Tổ, Vương Lâm cầm tiểu lệnh thủy tinh hóa tàn ảnh bay về theo đường Tôn Long, chỉ nửa tháng tới cái đài đầu tiên có trận truyền tống do Huyết Tổ lưu lại. Hắn mở ba trong bốn túi trữ vật cướp của Diêu Tích Tuyết, thu được tiên ngọc khổng lồ, hơn ngàn Ngọc phù huyết sắc, Huyết Hồn Đan cùng một la bàn huyết sắc, nhưng phát hiện đạo tử tuyến nghi cạm bẫy thần thức Huyết Tổ trên túi thứ tư nên không dám mở. Hắn xóa thần thức Diêu Tích Tuyết trong la bàn, lưu thần thức mình, rồi dùng ba ngày hiệu chỉnh trận cùng ba mươi ngày bố trí cấm chế biến trận truyền tống thành cạm bẫy cuốn người ngoài vào khe không gian. Kích hoạt la bàn, Vương Lâm truyền tống về một ngọn núi cổ ngoài Cổ Yêu Thành và nhận ra mình mới chỉ mất tích một năm. Hắn phá tan màn sương đen phòng hộ rồi tiến vào quân doanh Hắc Giáp quân, nơi Đô Thống cùng mười vạn Yêu binh và bốn thống lĩnh chờ sẵn, Tư Mã Viêm cung kính bên cạnh. Một tiếng quát Lui ra ẩn tiên lực Anh Biến hậu kỳ đại viên mãn đã chấn nhiếp khiến ba thống lĩnh tái mặt dừng lại; Đô Thống báo hắn đã bị Yêu Tướng bãi miễn chức rồi hóa thân Huyền Vũ trăm trượng chống cự. Vương Lâm thi triển Tịch Diệt Chỉ uy lực tăng vọt, hút cả huyết nhục yêu lực vài yêu binh khiến thiên địa biến sắc, quân doanh tối sầm."},{"chuong":527,"tieuDe":"Khu Vườn","tomTat":"Tại vùng đất Yêu Linh, người đàn ông vạm vỡ áo giáp đen dung nhập vào bóng Huyền Vũ biến ảo để chiến đấu, nhưng bị Vương Lâm dùng Tịch Diệt Chỉ ấn một cái phá tan Huyền Vũ từng đốt, áo giáp vỡ vụn, phun tiên huyết quỳ gối; Vương Lâm lúc này ở Anh Biến đại viên mãn, gần tiếp cận Vấn Đỉnh. Hắn chộp Tư Mã Viêm tới hỏi tung tích hai tùy tùng, rồi thi triển Sưu hồn thuật đọc ra việc Hổ Bào bị phế tu vi ném hắc lao rồi mất tích bí ẩn, còn Thập Tam bị bóp nát gân cốt và được Đô thống mang đi. Phẫn nộ, Vương Lâm vận Sát Lục Tiên quyết giết Tư Mã Viêm, luyện hóa toàn thân công phu hắn thành tia khí xám tụ ở tay phải. Đại hán áo giáp đen lộ tên là Tần Lâm, khai từng theo lệnh Yêu Tướng tìm người cường độ thân thể cao nên chữa thương cho Thập Tam rồi dâng tặng; hắn được Vương Lâm tha vì có công có tội. Tần Lâm tiết lộ Yêu Tướng bế quan nửa năm, mọi truyền tống trận đều bị phong kín từ bên trong, muốn vào chỉ có thể xông thẳng qua sáu cửa, rồi ôm ngực rút lui chữa thương. Vương Lâm tự nhận mình không hợp làm người tu đạo, chỉ cầu không thẹn lương tâm, quyết cứu Thập Tam dù tương đương chống lại cả Thiên Yêu Quận. Hắn hiện thân trước cửa thứ sáu canh phòng cẩn mật, thở sâu rồi thả tiên kiếm chứa Hứa Lập Quốc bay ra giữa tiếng gầm rú liên tục, chuẩn bị phá cửa."},{"chuong":528,"tieuDe":"Ngủ Say","tomTat":"Vương Lâm đơn thân xông vào cung điện Yêu Tướng, dùng tiên kiếm và gió lốc phá vỡ cửa thứ sáu rồi cửa thứ năm, đè bẹp mấy ngàn yêu binh và thả ba vỏ kiếm vô danh Chu Tước Tinh cùng Cấm Phiên chống lại luồng yêu khí của hơn mười vạn yêu binh. Cầu kiến Yêu Tướng hơn tuần hương không được hồi đáp, hắn thi triển Tịch Diệt Chỉ hút sạch huyết nhục yêu binh trăm dặm rồi phá cửa thứ tư. Lão già đầu bạc từng quản lý quân doanh Hắc Giáp hóa mãng xà yêu lực đánh lén, kinh ngạc trước sức mạnh vượt bậc của Vương Lâm, cuối cùng bỏ mạng khi con mãng xà va vào huyết long do Hóa Ma Chỉ tạo ra ở cửa thứ ba. Sau cửa ba, năm lão già tu vi ngang Anh Biến hậu kỳ bị Hoàng Tuyền Chỉ — sát chiêu chân chính do Tư Đồ Nam truyền — đẩy lùi phun huyết, khiến cửa thứ hai sụp đổ. Đệ nhất Đô Thống dáng thấp bé dùng quả cầu trắng tia chớp đen chặn Hoàng Tuyền Chỉ cách ba tấc nhưng bị đẩy lùi xô sập cửa thứ nhất, phun huyết bắn ra xa. Một người cao lớn bước ra tung Thập Băng Quyền ý nghênh chiến, vụ va chạm tạo sóng chấn lan mười dặm hủy lầu các và hóa tro yêu binh, đẩy Vương Lâm lùi hơn ba trượng. Suốt quá trình, Yêu Tướng vẫn bế quan không hề ra mặt, đúng như tiêu đề Ngủ Say."},{"chuong":529,"tieuDe":"Thu Hoạch","tomTat":"Vương Lâm dùng Sát Lục Tiên quyết luyện hóa khí xám thành bốn-năm luồng sát lục chi khí, đối đầu tuyệt chiêu Yêu Hải Bách Lãng của Yêu Tướng. Khi cấm chế và Huyết sắc Ngọc phù đều bị sóng yêu khí phá vỡ, Vương Lâm dùng phù văn màu vàng từ tượng đá thứ hai vẽ ba nét phù văn thần thông bắn khí xám xuyên Yêu Hải, rồi tạo một chưởng ấn hư ảo mang khí thế hủy thiên diệt địa. Chưởng ấn thực ra vô lực nhưng buộc đối phương không dám đánh cuộc mạng sống. Yêu Tướng lộ tên thật Mạc Lệ Hải, khai luyện pháp bảo cần thân thể mười tám người, phong Vương Lâm làm Tả dực đệ nhất phó tướng, hẹn so đấu tại Thiên Yêu thành ba tháng sau và thả Thập Tam. Sau khi Vương Lâm rời đi, năm lão giả bàn luận, Mạc Lệ Hải thừa nhận chưởng kia chín phần mười là giả nhưng không dám liều, đồng thời nhắc bí ẩn tu vi Vương Lâm tăng vọt. Vương Lâm tìm Hổ Bào khắp Cổ Yêu thành và hắc lao nhưng không thấy dấu vết linh hồn, rồi về bộ lạc Luyện Hồn được toàn tộc và Âu Dương Hoa quỳ nghênh lão tổ. Ba ngày sau hắn đánh thức Thập Tam, hồi tưởng chiến lợi phẩm từ Cự Ma Tộc lão tổ gồm bình máu Cổ Thần, một tia nguyên thần Pháp Cổn Luân và một ngọc giản."},{"chuong":530,"tieuDe":"Thực Lực Của Anh Biến Kỳ Đại Viên Mãn","tomTat":"Trong Luyện Hồn cốc, Vương Lâm ghi nhớ trọn chín tầng công pháp luyện thể Cự Linh Cửu Tu trong ngọc giản, xóa ba tầng cuối rồi chép sáu tầng đầu vào một ngọc giản xanh ném cho Thập Tam; Thập Tam quỳ đập đầu thề trung thành, tôn hắn làm Lão tổ và được dặn bảo vệ bộ tộc Luyện Hồn trước khi bị gió cuốn ra ngoài cốc. Vương Lâm ngồi dưỡng hồn dưới hắc vụ do Tôn Hồn Phiên hóa thành, lo ba tháng sau phải tới kinh thành Thiên Yêu quận nên không thể mang Tôn Hồn Phiên đi xa. Ở chiến trường cổ phía Tây trong lãnh thổ Yêu Linh, một thanh niên dùng hơn trăm tiểu kỳ đen đánh thức và thu hút linh hồn ngủ say, dưới sự giám sát của một lão già hắc y. Thanh niên xưng là Hổ Bào, vốn là thuộc hạ cũ của Vương Lâm; hắn kể vì Vương Lâm mà bị Tư Mã Viêm ném vào hắc lao, chờ cứu vô vọng nên ôm hận, nay thề báo thù cả Vương Lâm lẫn Tư Mã Viêm. Lão già hắc y cho biết chỉ cứu Hổ Bào vì hắn có Luyện Hồn Thuật kỳ dị, đã truyền cho hắn Diệt Thế Áp Nguyên Công rồi hóa khói biến mất. Sau đó lão vào hắc tháp mười tầng, quỳ trước bộ áo giáp cổ của chủ nhân, báo tin Yêu Đế Thiên Yêu quận ngàn năm trước bị ngừng ở bước đột phá cuối và nhận tin tức từ u quang trong giáp. Lão lên kế hoạch dùng Luyện Hồn Thuật cùng công pháp, đan dược và khẩu quyết của chủ nhân để biến Hổ Bào thành Yêu Vệ làm thí nghiệm, dự định sẽ tới bộ tộc Luyện Hồn thăm dò nếu thành công."},{"chuong":531,"tieuDe":"Cứu Thập Tam","tomTat":"Trong sơn cốc bộ lạc Luyện Hồn, Vương Lâm thả cấm chế bao bọc Diêu Tích Tuyết — đang bị Sinh Chi Lạc Ấn bơm sinh cơ vĩnh viễn không cho chết — đề nghị giảm phong ấn 50 năm đổi một câu trả lời nhưng bị nàng mắng chửi, dọa sẽ để phụ thân Huyết Tổ trả thù. Hắn lôi ra cây châm đỏ do tia tinh khí nguyên thần cuối cùng của nàng hóa thành giấu trong miệng định chặn sinh cơ tự sát, rồi phá luôn tâm cảnh hận nhập đạo bằng cách chấn nát quần áo và kích thích tuần hoàn cấm chế, cuối cùng thu nàng thành quả cầu cấm chế cất vào túi trữ vật, tiếc rằng tu vi chưa tới Vấn Đỉnh nên chưa dùng được Sưu Hồn Thuật. Hai tháng sau, sát hẹn ước với Yêu tướng, Vương Lâm dặn Âu Dương Hoa phái mấy trăm tộc nhân tiềm nhập các bộ lạc lớn nhỏ — dùng Hồn Phách Thủ Thần chống lại Linh Thang Loạn Thần — để truyền Luyện Hồn Thuật, đặt mục tiêu hơn trăm vạn tộc nhân; trao ngọc giản phần hai (thần thông rút phách) chỉ cho chi chính. Hắn thu Tôn Hồn Phiên vào nguyên thần, ném nhiều Hồn Phiên thường thay thế phủ kín bầu trời rồi rời đi, Âu Dương Hoa quỳ tiễn xưng lão tổ. Vương Lâm bay tới Cổ Yêu thành gặp Yêu tướng Mạc Lực Hải đang đứng trên tường thành cửa đông — Yêu tướng tiếc Thập Tam (bộ thứ mười tám của Thập Bát Yêu Ma Thân) bị Vương Lâm mang đi, mưu vào vòng ba cuộc chiến Yêu tướng để giành tư cách vào Cổ Yêu điện và chức phó soái. Hai người cùng qua ba truyền tống trận hướng kinh thành Thiên Yêu quận, nơi Vương Lâm ấp ủ ý bắt một trong mười người Đại La Kiếm Tông hỏi nơi Chu Dật bị phong ấn."},{"chuong":532,"tieuDe":"Một Chưởng","tomTat":"Chương mở ra toàn cảnh kinh đô Thiên Yêu quận: Thiên Yêu thành do chín tòa thành nhỏ ghép lại (tám thành ngoài theo bát quái, thành giữa là Đế Đô — tẩm cung của Yêu Đế), địa hình quanh thành như chín Cự Long quấn nhau cùng hướng về đầm Long Đàm nơi có Cổ Yêu Điện, sáng sớm phủ long khí có thể thổ nạp tăng tu vi. Tại truyền tống trận thứ mười bốn, một đội trưởng Yêu binh cùng thuộc hạ Nhị Cẩu trò chuyện, tiết lộ cứ ba trăm năm Đế Quân lại đích thân quan sát cuộc chiến Yêu tướng; lần này đặc biệt vì phải chọn hai vị soái mới thay hai phó soái tử trận trong đại chiến với Hỏa Yêu quận hai trăm năm trước, nên các Yêu tướng tấp nập về kinh. Truyền tống trận thứ mười bốn sáng lên, Mạc Lệ Hải cùng Vương Lâm bước ra, được Yêu binh cung nghênh. Mạc Lệ Hải mời Vương Lâm về phủ ở Hồng thành vì kinh thành đang hỗn tạp thế lực, giới thiệu hắn là “Vương tướng” bạn tốt. Mười chín kỵ binh giáp đen Hóa Thần dưới trướng quỳ tham kiến Chủ tướng rồi tham kiến cả Vương tướng. Cả đoàn phóng ngựa về phủ thì phía trước vang tiếng vó ngựa, Mạc Lệ Hải trầm sắc tăng tốc, còn Vương Lâm lóe mắt nhận ra một người quen."},{"chuong":533,"tieuDe":"Hổ Bào, Lão Già Và Áo Giáp","tomTat":"Trên quân đạo, đoàn người Mạc Lệ Hải chạm trán hai kỵ sĩ phóng tới: Thạch Tiễn tóc tím mặt sẹo mặc áo giáp thanh sắc và một tên gầy gò nhận ra Vương Lâm. Thạch Tiễn tung Lục Chỉ Kiếm Quyết đối Thập Băng Quyền Ý của Mạc Lệ Hải; nhờ Vương Lâm trợ một điểm xảo diệu, chiến mã Thạch Tiễn nứt bốn chân còn mã Mạc Lệ Hải bình an, cao thấp đã rõ. Tên gầy gò lộ thân phận là Trần Đào — sư huynh đồng hệ của Vương Lâm, bị Đại La Kiếm Tông đánh trọng thương tụt từ Vấn Đỉnh trung kỳ xuống Anh Biến viên mãn; Vương Lâm tặng túi Tuy Bình đan thiện chí rồi rời đi. Hai bên bàn về Thần Thông Tam Thức của Mạc Lệ Hải và kế luyện Thiên Nguyên đan khôi phục cho Trần Đào, đồng thời lộ tên Thạch Tiễn là kình địch cuộc chiến Yêu tướng. Vương Lâm vào Mạc phủ tu luyện bốn ngày trong khi Mạc Lệ Hải vào Đế Đô gặp Yêu Đế và thăm hỏi các Yêu tướng. Một lần luyện Sát Lục Tiên Quyết kéo dài bảy ngày, Sát Lục Chi Khí khiến hai quân sĩ phát điên sát khí và tiêu tán hơn nửa Yêu lực, khiến Vương Lâm sinh nghi vì sao giết nhiều mà Sát Lục Chi Khí lại ít."},{"chuong":534,"tieuDe":"Hỏi Diêu Tích Tuyết","tomTat":"Vương Lâm ngồi trong sân dùng hồi ức làm chậm từng lần luyện hóa Sát Lục Chi Khí để tìm quy luật, nhưng không thấy điểm chung — kể cả lần nén giận giết Tư Mã Viêm luyện được một đạo vẫn không giải thích thông. Hắn xác định Sát Lục Tiên Quyết là trọng điểm chuyến vào lãnh thổ Yêu linh, năm xưa học để chống Thác Sâm; nay có thêm Huyết Hồn Đan phối Sinh Cơ Lạc Ấn đủ bảo vệ tính mệnh, song vẫn quyết thí nghiệm và thôi diễn hàng loạt để lĩnh ngộ phần huyền bí còn ẩn. Hắn gọi hai quân sĩ dẫn đường, giấu tiên lực giả làm thư sinh ra cửa đông Hồng thành dạo phố, nhưng giữa cảnh đông vui lại thấy mình cô độc lạc lõng. Khi trời tối, tiếng đàn bi thương từ một thuyền hoa trên nhánh sông Thiên Yêu thành khiến hắn dừng bước, gợi nhớ tiếng đàn của Uyển Nhi ở sơn cốc Chu Tước Tinh; hắn vuốt mi tâm như chạm vào Lý Mộ Uyển trong Hạt Châu Thiên Nghịch và thề sẽ gặp lại nàng. Khi thuyền đi xa và bóng hắn tan vào đêm, cô gái đánh đàn như có linh tính xoay nhìn về con đường tối đen, mơ hồ thấy một hình bóng cô độc đang tan biến. Nàng gảy một tiếng đàn bi thương, lộ ra mình bị mù — trước mắt chỉ là khoảng đen kịt — ngồi đầu thuyền như đóa sen không nhiễm bụi, cô độc đón gió mà không ai thật sự lắng nghe."},{"chuong":535,"tieuDe":"Người Quen","tomTat":"Vương Lâm đứng bên bờ sông Hồng thành cả ngày, cảm nhận được trong Hồng lao — một trong tứ Đại Lao ngục của kinh đô, giam hơn vạn trọng phạm — ẩn chứa một cỗ yêu khí cường đại không kém Mạc Lệ Hải. Hắn về Mạc phủ đề nghị được đưa vào Hồng lao để giết chóc tu luyện, và để chứng minh giá trị đã vung tay tạo năm đạo sát lục khí hóa thành năm con thương long; chúng bị Mạc Lệ Hải đánh tan thì dung hợp lại, len qua quyền phong chấn động yêu giáp khiến hắn kinh ngạc, cuối cùng chốt cho vào bảy ngày. Sau khi Vương Lâm đi, Mạc Lệ Hải tự nhủ thứ sát khí xám sắc bén như yêu kiếm lại có biến hóa dẫn động sinh cơ là cực kỳ đáng sợ, nên quyết giữ quan hệ tốt. Suốt ba ngày chờ Mạc Lệ Hải sắp xếp, Vương Lâm không tu luyện mà ra bờ sông uống rượu nghe tiếng đàn bi thương từ hoa thuyền để tẩy rửa tâm linh, độc thoại về đạo nghịch thiên cô độc và chí thoát khỏi thân phận con kiến hôi. Đến khi mọi việc sắp xong, một ngày tiếng đ��n đứt đoạn; Vương Lâm đứng dậy nhìn hoa thuyền xa dần rồi rời đi, còn nữ tử đánh đàn quay đầu nhìn theo bóng hắn. Một khách nhân giọng bình thản bên cạnh gọi tên nàng là Minh Huyên và lạnh lùng buộc nàng đổi bài khác, hé lộ nàng đang bị một thế lực bí ẩn khống chế."},{"chuong":536,"tieuDe":"Loạn Kinh Đô","tomTat":"Vương Lâm nghe một nữ tử bị ép gảy khúc đàn vui mà ẩn tiếng khóc, cước bộ sững lại nhưng không quay đầu mà đi tiếp. Nửa đêm hắn cùng Mạc Lệ Hải phóng tới Hồng lao ở Hồng thành, được nam tử họ Hứa tu vi Anh Biến hậu kỳ đại viên mãn tiếp nhận; Mạc Lệ Hải trả ba tầng đầu Thập Băng Quyền Ý để đổi cho Vương Lâm một suất tu luyện rồi rời đi. Hứa cho Vương Lâm một tháng trong lồng giam dưới lòng đất giết phạm nhân nghiên cứu sát lục khí, nhưng sau năm ngày hắn vẫn cách một tầng giấy mỏng vì thiếu sát tâm. Hứa chỉ điểm sát tâm như kiếm chưa rời vỏ, ra điều kiện đưa Vương Lâm tới nơi cảm nhận sát lục chân chính để đổi việc giết yêu tướng Thạch Tiễn, rồi tiết lộ bí mật tầng đáy Hồng lao là thế giới máu nuôi yêu kiếm của yêu đế. Vương Lâm ngồi vào hồ máu, hòa vào chu kỳ chém giết, mất ý thức thi triển Tịch Diệt Chỉ và Hóa Ma Chỉ, trở thành một trong hơn trăm người sống sót và ngộ ra cần có sát lục chi tâm. Qua nhiều ngày chém giết, người sống sót giảm dần còn huyết sát vụ trên thân Vương Lâm dày tới hơn trăm trượng. Yêu kiếm ngân long hiện ra hút sát vụ và xé tan kẻ phản kháng; cuối cùng chỉ còn Vương Lâm và một thanh niên tóc đen khi ngân long lại hút mạnh."}];
